from collections import deque, Counter

class SlidingWindowCounter:
    def __init__(self, window_seconds: int):
        self.window_seconds = window_seconds
        # Synchronized deques act as a queue for O(1) popleft operations
        self.timestamps = deque()
        self.categories = deque()
        # Counter maintains frequencies of categories currently in the active window
        self.counter = Counter()

    def add(self, category: str, timestamp: float) -> None:
        # Evict expired events from the front of the window
        while self.timestamps and self.timestamps[0] <= timestamp - self.window_seconds:
            old_cat = self.categories.popleft()
            self.timestamps.popleft()
            self.counter[old_cat] -= 1
            if self.counter[old_cat] == 0:
                del self.counter[old_cat]

        # Enqueue new event
        self.timestamps.append(timestamp)
        self.categories.append(category)
        self.counter[category] += 1

    def get_counts(self, current_time: float) -> dict:
        # The counter already reflects the current window state after add()
        return dict(self.counter)

    def get_unique_count(self, current_time: float) -> int:
        return len(self.counter)

