import argparse
import re
import sys


def snake_to_camel(text):
    if not text:
        return text
    components = text.split('_')
    return components[0] + ''.join(x.title() for x in components[1:])


def camel_to_snake(text):
    if not text:
        return text
    s = re.sub('(.)([A-Z][a-z]+)', r'\1_\2', text)
    return re.sub('([a-z0-9])([A-Z])', r'\1_\2', s).lower()


def pascal_to_camel(text):
    if not text:
        return text
    return text[0].lower() + text[1:]


def main():
    parser = argparse.ArgumentParser(description='Convert text case formats.')
    parser.add_argument('input_text', help='Text to convert')
    parser.add_argument('--to', required=True, choices=['snake', 'camel', 'pascal'], help='Target format')
    parser.add_argument('--from', dest='from_format', required=True, choices=['snake', 'camel', 'pascal'], help='Source format')
    args = parser.parse_args()

    text = args.input_text
    result = ''

    if args.from_format == 'snake':
        if args.to == 'camel':
            result = snake_to_camel(text)
        elif args.to == 'pascal':
            result = snake_to_camel(text).title()
    elif args.from_format == 'camel':
        if args.to == 'snake':
            result = camel_to_snake(text)
        elif args.to == 'pascal':
            result = text[0].upper() + text[1:]
    elif args.from_format == 'pascal':
        if args.to == 'snake':
            result = camel_to_snake(pascal_to_camel(text))
        elif args.to == 'camel':
            result = pascal_to_camel(text)

    print(result)


if __name__ == '__main__':
    main()
```

