import argparse
import requests
import os
import time
import hashlib
import json
from pathlib import Path
from typing import Optional

class DownloadError(Exception):
    pass

class CacheManager:
    def __init__(self, cache_dir: str):
        self.cache_dir = Path(cache_dir)
        self.meta_file = self.cache_dir / ".meta.json"
        self._ensure_dir()

    def _ensure_dir(self):
        self.cache_dir.mkdir(parents=True, exist_ok=True)

    def is_fresh(self, url: str, ttl: int) -> bool:
        meta = self._load_meta()
        if url not in meta:
            return False
        entry = meta[url]
        if entry.get("status") == "expired":
            return False
        elapsed = time.time() - entry.get("timestamp", 0)
        if elapsed < ttl:
            return True
        return False

    def get_cached_path(self, url: str) -> Optional[str]:
        meta = self._load_meta()
        return meta.get(url, {}).get("path")

    def update_meta(self, url: str, status: str, path: Optional[Path] = None, headers: Optional[dict] = None):
        meta = self._load_meta()
        meta[url] = {
            "status": status,
            "path": str(path) if path else None,
            "headers": headers or {},
            "timestamp": time.time()
        }
        self._save_meta(meta)

    def _load_meta(self) -> dict:
        if not self.meta_file.exists():
            return {}
        try:
            with open(self.meta_file, "r") as f:
                return json.load(f)
        except (json.JSONDecodeError, PermissionError):
            return {}

    def _save_meta(self, meta: dict):
        with open(self.meta_file, "w") as f:
            json.dump(meta, f, indent=2)


def fetch_with_retry(url: str, max_retries: int, timeout: int) -> requests.Response:
    last_exception = None
    for attempt in range(max_retries):
        try:
            response = requests.get(url, timeout=timeout)
            response.raise_for_status()
            return response
        except requests.RequestException as e:
            last_exception = e
            if attempt < max_retries - 1:
                backoff = 2 ** attempt
                time.sleep(backoff)
    raise DownloadError(f"Failed after {max_retries} retries: {last_exception}")


def generate_filename(url: str) -> str:
    ext = "bin"
    hash_val = hashlib.md5(url.encode()).hexdigest()
    return f"{hash_val}.{ext}"


def main(argv: Optional[list] = None) -> int:
    parser = argparse.ArgumentParser(description="Smart Downloader CLI")
    parser.add_argument("--url", required=True, help="URL to download")
    parser.add_argument("--output-dir", default="./downloads", help="Output directory")
    parser.add_argument("--max-retries", type=int, default=3, help="Max retry attempts")
    parser.add_argument("--timeout", type=int, default=10, help="Request timeout in seconds")
    parser.add_argument("--cache-ttl", type=int, default=3600, help="Cache TTL in seconds")
    parser.add_argument("--cache-dir", default="./cache", help="Cache directory")

    args = parser.parse_args(argv)

    cache = CacheManager(args.cache_dir)
    output_dir = Path(args.output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)

    if cache.is_fresh(args.url, args.cache_ttl):
        cached_path = cache.get_cached_path(args.url)
        if cached_path and os.path.exists(cached_path):
            print(f"[CACHE HIT] Using cached content from {cached_path}")
            return 0

    print(f"[INFO] Fetching {args.url}...")
    try:
        response = fetch_with_retry(args.url, args.max_retries, args.timeout)
    except DownloadError as e:
        print(f"[ERROR] {e}", file=__import__('sys').stderr)
        return 1

    filename = generate_filename(args.url)
    filepath = output_dir / filename

    with open(filepath, "wb") as f:
        f.write(response.content)

    cache.update_meta(args.url, "cached", filepath, {
        "etag": response.headers.get("etag", ""),
        "status_code": response.status_code
    })

    print(f"[SUCCESS] Saved to {filepath}")
    return 0
