import re
import sys
from typing import Dict, Set, Optional


class ConfigInterpolator:
    def __init__(self, environment: Dict[str, str]):
        self.env = environment
        self.visited: Set[str] = set()

    def interpolate(self, template: str) -> str:
        if not template:
            return ""

        result = []
        i = 0
        n = len(template)

        while i < n:
            if template[i:i+2] == '${':
                # Find the matching closing brace, handling nesting
                depth = 1
                j = i + 2
                while j < n and depth > 0:
                    if template[j:j+2] == '${':
                        depth += 1
                        j += 1
                    elif template[j] == '}':
                        depth -= 1
                    j += 1

                if depth != 0:
                    raise ValueError("Mismatched braces in template")

                # Extract content between ${ and }
                content = template[i+2:j-1]

                # Parse variable name and optional default value
                sep_idx = content.find(':-')
                if sep_idx != -1:
                    var_name = content[:sep_idx]
                    default_val = content[sep_idx+2:]
                else:
                    var_name = content
                    default_val = None

                if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', var_name):
                    raise ValueError(f"Invalid variable name: {var_name}")

                if var_name in self.visited:
                    raise ValueError(f"Circular reference detected: {var_name}")

                self.visited.add(var_name)
                try:
                    if var_name in self.env:
                        value = self.env[var_name]
                    elif default_val is not None:
                        value = self.interpolate(default_val)
                    else:
                        value = ""
                    result.append(value)
                finally:
                    self.visited.discard(var_name)

                i = j
            else:
                result.append(template[i])
                i += 1

        return "".join(result)

    def run(self):
        if len(sys.argv) < 2:
            print("Usage: python interpolator.py '<template>'", file=sys.stderr)
            sys.exit(1)

        template = sys.argv[1]
