    """Create a new user. Returns (user_dict, status_code, error_message)."""
    # Check for duplicate email
    for user in USER_DB.values():
        if user['contact'] == email:
            return None, CONFLICT, "A user with this email already exists."

    new_id = max(USER_DB.keys()) + 1
    new_user = {
