import json
import hashlib
import time
from typing import Dict, List, Tuple, Any, Optional

# Constants for status codes, headers, and limits
HTTP_OK = 200
HTTP_CREATED = 201
HTTP_UNAUTHORIZED = 401
HTTP_BAD_REQUEST = 400
HTTP_NOT_FOUND = 404
HTTP_METHOD_NOT_ALLOWED = 405
HTTP_TOO_MANY_REQUESTS = 429
CONTENT_TYPE_JSON = "application/json"
DEFAULT_REMOTE_ADDR = "127.0.0.1"
CACHE_TTL_SECONDS = 60
RATE_LIMIT_MAX = 100
BEARER_PREFIX = "Bearer "

class ApiResponse:
    """Standardized response builder for WSGI-compatible output."""
    def __init__(self, status_code: int, body: Any):
        self.status_code = status_code
        self.headers = {"Content-Type": CONTENT_TYPE_JSON}
        self.body_bytes = json.dumps(body).encode("utf-8")

    def to_tuple(self) -> Tuple[int, List[Tuple[str, str]], bytes]:
        return (self.status_code, list(self.headers.items()), self.body_bytes)

class RateLimiter:
    """Tracks request timestamps per IP to enforce rate limits."""
    def __init__(self):
        self.request_timestamps: Dict[str, List[float]] = {}

    def is_allowed(self, ip_address: str) -> bool:
        now = time.time()
        if ip_address not in self.request_timestamps:
            self.request_timestamps[ip_address] = [now]
            return True
        if now - self.request_timestamps[ip_address][0] > CACHE_TTL_SECONDS:
            self.request_timestamps[ip_address] = [now]
            return True
        if len(self.request_timestamps[ip_address]) >= RATE_LIMIT_MAX:
            return False
        self.request_timestamps[ip_address].append(now)
        return True

class AuthManager:
    """Validates Bearer tokens against a registry."""
    def __init__(self, token_registry: Dict[str, str]):
        self.token_registry = token_registry

    def authenticate(self, headers: Dict[str, str]) -> Optional[str]:
        auth_header = headers.get("Authorization", "")
        if auth_header.startswith(BEARER_PREFIX):
            token = auth_header[len(BEARER_PREFIX):]
            return self.token_registry.get(token)
        return None

class CacheManager:
    """Simple in-memory key-value cache."""
    def __init__(self):
        self.store: Dict[str, Any] = {}

    def get_or_set(self, key: str, value: Any) -> Any:
        if key not in self.store:
            self.store[key] = value
        return self.store[key]

class APIServer:
    """Refactored request handler with clear separation of concerns."""
    def __init__(self):
        self.rate_limiter = RateLimiter()
        self.auth_manager = AuthManager({
            "admin": "secret123",
            "user1": "pass456",
            "user2": "pass789"
        })
        self.cache = CacheManager()
        self.routes: Dict[str, Any] = {
            "/api/v1/users": self._handle_users,
            "/api/v1/data": self._handle_data
        }

    def handle_request(self, env: Dict[str, Any]) -> Tuple[int, List[Tuple[str, str]], bytes]:
        ip_address = env.get("REMOTE_ADDR", DEFAULT_REMOTE_ADDR)
        if not self.rate_limiter.is_allowed(ip_address):
            return ApiResponse(HTTP_TOO_MANY_REQUESTS, {"error": "Rate limit exceeded"}).to_tuple()

        user = self.auth_manager.authenticate(env.get("HTTP_HEADERS", {}))
        if not user:
            return ApiResponse(HTTP_UNAUTHORIZED, {"error": "Authentication required"}).to_tuple()

        method = env["REQUEST_METHOD"]
        path = env["PATH_INFO"]
        handler = self.routes.get(path)

        if not handler:
            return ApiResponse(HTTP_NOT_FOUND, {"error": "Endpoint not found"}).to_tuple()

        if method == "GET":
            return self._handle_get(path, env, user)
        elif method == "POST":
            return self._handle_post(env, user)

        return ApiResponse(HTTP_METHOD_NOT_ALLOWED, {"error": "Unsupported HTTP method"}).to_tuple()

    def _handle_get(self, path: str, env: Dict[str, Any], user: str) -> Tuple[int, List[Tuple[str, str]], bytes]:
        query_string = env.get("QUERY_STRING", "")
        params = self._parse_query_string(query_string)
        result = self.routes[path](params, user)

        cache_key = hashlib.md5(f"{path}{query_string}{user}".encode()).hexdigest()
        cached_result = self.cache.get_or_set(cache_key, result)

        return ApiResponse(HTTP_OK, cached_result).to_tuple()

    def _handle_post(self, env: Dict[str, Any], user: str) -> Tuple[int, List[Tuple[str, str]], bytes]:
        body_raw = env.get("wsgi.input").read().decode("utf-8") if "wsgi.input" in env else ""
        try:
            payload = json.loads(body_raw)
        except json.JSONDecodeError:
            return ApiResponse(HTTP_BAD_REQUEST, {"error": "Invalid JSON payload"}).to_tuple()

        result = self.routes[env["PATH_INFO"]](payload, user)
        return ApiResponse(HTTP_CREATED, result).to_tuple()

    @staticmethod
    def _handle_users(params_or_body: Any, user: str) -> Dict[str, Any]:
        return {"user": user, "action": "retrieved_users", "params": params_or_body}

    @staticmethod
    def _handle_data(params_or_body: Any, user: str) -> Dict[str, Any]:
        return {"user": user, "action": "processed_data", "payload": params_or_body}

    @staticmethod
    def _parse_query_string(qs: str) -> Dict[str, str]:
        if not qs:
            return {}
        return dict(pair.split("=", 1) for pair in qs.split("&") if "=" in pair)

def handle_patch(self, req: Request) -> Response:
    # 1. Extract product ID from path
    path_parts = req.path.split("/")
    if len(path_parts) < 3 or path_parts[1] != "products":
        return Response(404, {"Content-Type": "application/json"}, {"error": "Invalid path"})

    product_id = path_parts[2]

    # 2. Validate request body and content-type
    if req.body is None:
        return Response(400, {"Content-Type": "application/json"}, {"error": "Request body is required"})

    content_type = req.headers.get("content-type", "")
    if "application/json" not in content_type:
        return Response(415, {"Content-Type": "application/json"}, {"error": "Unsupported Media Type"})

    try:
        updates = json.loads(req.body)
    except json.JSONDecodeError:
        return Response(400, {"Content-Type": "application/json"}, {"error": "Invalid JSON"})

    if not isinstance(updates, dict):
        return Response(400, {"Content-Type": "application/json"}, {"error": "Body must be a JSON object"})

    # 3. Check product existence
    if product_id not in self.store.products:
        return Response(404, {"Content-Type": "application/json"}, {"error": "Product not found"})

    # 4. Apply partial update (RFC 7396 null handling)
    product = self.store.products[product_id]
    for key, value in updates.items():
        if value is None:
            product.pop(key, None)
        else:
            product[key] = value

    # 5. Validate constraints on the resulting product
    errors = []

    if "price" in product:
        p = product["price"]
        if not isinstance(p, (int, float)) or p <= 0:
            errors.append("price must be a positive number")

    if "stock" in product:
        s = product["stock"]
        if not isinstance(s, int) or s < 0:
            errors.append("stock must be a non-negative integer")

    if "name" in product:
        n = product["name"]
        if not isinstance(n, str) or not n.strip():
            errors.append("name must be a non-empty string")

    if errors:
        return Response(422, {"Content-Type": "application/json"}, {"errors": errors})

    # 6. Save and return
    self.store.products[product_id] = product
    return Response(200, {"Content-Type": "application/json"}, product)

