    if not isinstance(data['quantity'], int) or data['quantity'] < 0:
        return jsonify({"error": "Quantity must be a non-negative integer"}), 400

    new_item = {
        "id": len(inventory) + 1,
        "sku": data['sku'],
        "quantity": data['quantity']
    }
    inventory.append(new_item)
