def filter_logs(input_path: str, output_path: str, start_date: str, end_date: str, target_level: str) -> dict:
    try:
        start_dt = datetime.strptime(start_date, "%Y-%m-%d")
        end_dt = datetime.strptime(end_date, "%Y-%m-%d").replace(hour=23, minute=59, second=59)

        stats = {"processed": 0, "skipped": 0, "errors": 0}
        matches = []

        with open(input_path, 'r', encoding='utf-8') as f_in:
            for line in f_in:
                line = line.strip()
                if not line:
                    continue

                try:
                    parts = line.split(' ', 2)
                    if len(parts) < 3:
                        raise ValueError("Insufficient parts")

                    date_str, time_str, rest = parts
                    dt = datetime.strptime(f"{date_str} {time_str}", "%Y-%m-%d %H:%M:%S")

                    level_part = rest.split(' ', 1)[0]
                    if not (level_part.startswith('[') and level_part.endswith(']')):
                        raise ValueError("Invalid level format")

                    level = level_part[1:-1]

                    if start_dt <= dt <= end_dt and level == target_level:
                        matches.append(line)
                        stats["processed"] += 1
                    else:
                        stats["skipped"] += 1
                except (ValueError, IndexError):
                    stats["errors"] += 1

        matches.sort(key=lambda x: x[:19])

        with open(output_path, 'w', encoding='utf-8') as f_out:
