        return None

import os
import stat

def rotate_log_file(file_path: str, max_size_bytes: int, max_backups: int = 5) -> None:
    """
    Performs a safe log rotation on a given file.

    Args:
        file_path: Path to the log file to rotate.
        max_size_bytes: Maximum allowed size of the log file in bytes before rotation.
        max_backups: Maximum number of backup files to retain.
    """
    if max_backups <= 0:
        raise ValueError("max_backups must be a positive integer")

    # Check if file exists and size constraint
    if not os.path.exists(file_path):
        return

    try:
        current_size = os.path.getsize(file_path)
    except OSError:
        return

    if current_size <= max_size_bytes:
        return

    # 1. Remove the oldest backup if it exists
    oldest_backup = f"{file_path}.{max_backups}"
    if os.path.exists(oldest_backup):
        try:
            os.remove(oldest_backup)
        except OSError:
            # If we can't remove the oldest, we abort to prevent data corruption
            # In a production system, you might log this error.
            return

    # 2. Shift existing backups
    # Iterate downwards to avoid overwriting the next backup
    for i in range(max_backups - 1, 0, -1):
        src = f"{file_path}.{i}"
        dst = f"{file_path}.{i + 1}"
        if os.path.exists(src):
            try:
                os.replace(src, dst)
            except OSError:
                # If shift fails, abort rotation
                return

    # 3. Rotate the current log file to .1
    new_first_backup = f"{file_path}.1"
    try:
        os.replace(file_path, new_first_backup)
    except OSError:
        return

    # 4. Create a new empty file
    # Use os.open for low-level control, then wrap in file object
    fd = os.open(file_path, os.O_CREAT | os.O_WRONLY | os.O_TRUNC, stat.S_IRUSR | stat.S_IWUSR)
    try:
        os.close(fd)
    except OSError:
        # Cleanup partial creation if close fails
        if os.path.exists(file_path):
            os.remove(file_path)
        raise

