import re

class ConfigParser:
    def __init__(self):
        self.indent_level = 0
        self.data = {}
        self._stack = [self.data]

    def parse(self, text: str) -> dict:
        self.data = {}
        self._stack = [self.data]
        self.indent_level = 0
        lines = text.splitlines()
        for i, line in enumerate(lines):
            stripped = line.strip()
            if not stripped or stripped.startswith('#'):
                continue

            current_indent = len(line) - len(line.lstrip())
            if current_indent % 4 != 0:
                raise ValueError(f"Line {i+1}: Indentation must be a multiple of 4 spaces.")

            indent_lvl = current_indent // 4
            while len(self._stack) - 1 > indent_lvl:
                self._stack.pop()

            current_dict = self._stack[-1]

            if ':' not in stripped and '=' not in stripped:
                raise ValueError(f"Line {i+1}: Invalid syntax. Expected key: value format.")

            key, value = stripped.split(':', 1) if ':' in stripped else stripped.split('=', 1)
            key = key.strip()
            value = value.strip()

            if not value:
                new_dict = {}
                current_dict[key] = new_dict
                self._stack.append(new_dict)
                continue

            current_dict[key] = self._parse_value(value)
        return self.data

    def _parse_value(self, val: str):
        val = val.strip()
        if val.startswith('[') and val.endswith(']'):
            inner = val[1:-1]
            if not inner.strip():
                return []
            return [self._parse_value(v.strip()) for v in inner.split(',')]
        if val.lower() == 'true':
            return True
        if val.lower() == 'false':
            return False
        try:
            return int(val)
        except ValueError:
            pass
        try:
            return float(val)
        except ValueError:
            pass
        if (val.startswith('"') and val.endswith('"')) or (val.startswith("'") and val.endswith("'")):
            return val[1:-1]
        return val
