def parse_config(text: str) -> dict:
    config = {}
    current_section = None
    current_key = None
    current_value_lines = []

    for line in text.splitlines():
        stripped = line.strip()
        if not stripped or stripped.startswith('#'):
            continue

        if stripped.startswith('[') and stripped.endswith(']'):
            current_section = stripped[1:-1]
            config.setdefault(current_section, {})
            current_key = None
            current_value_lines = []
            continue

        if current_section is None:
            continue

        indent = len(line) - len(line.lstrip())
        if indent >= 2 and current_key is not None:
            current_value_lines.append(stripped)
            continue

        if current_key is not None:
            config[current_section][current_key] = ' '.join(current_value_lines).strip()

        del_idx = -1
        for i, char in enumerate(stripped):
            if char in '=:':
                del_idx = i
                break
        if del_idx == -1:
            continue

        current_key = stripped[:del_idx].strip()
        raw_value = stripped[del_idx+1:].strip()

        comment_idx = raw_value.find('#')
        if comment_idx != -1:
            raw_value = raw_value[:comment_idx].strip()

        if not raw_value:
            current_value_lines = []
        else:
            current_value_lines = [raw_value]

    if current_key is not None:
        config[current_section][current_key] = ' '.join(current_value_lines).strip()

    return config

def parse_value(self):
    token = self.peek()

    # Handle primitive types
    if token['type'] in ('INT', 'FLOAT', 'BOOL', 'NULL'):
        self.advance()
        val = token['val']
        if token['type'] == 'INT':
            return int(val)
        elif token['type'] == 'FLOAT':
            return float(val)
        elif token['type'] == 'BOOL':
            return val == 'true'
        else:  # NULL
            return None

    # Handle quoted strings with escape sequences
    if token['type'] == 'STRING':
        self.advance()
        raw = token['val']
        unescaped = []
        i = 0
        while i < len(raw):
            if raw[i] == '\\':
                i += 1
                if i < len(raw):
                    c = raw[i]
                    if c == 'n':
                        unescaped.append('\n')
                    elif c == 't':
                        unescaped.append('\t')
                    elif c == '\\':
                        unescaped.append('\\')
                    elif c == '"':
                        unescaped.append('"')
                    else:
                        # Unknown escape, keep as is or error? 
                        # Keeping as is for robustness
                        unescaped.append(c)
            else:
                unescaped.append(raw[i])
            i += 1
        return ''.join(unescaped)

    # Handle lists
    if token['type'] == 'LBRACKET':
        self.advance()
        lst = []
        while self.peek()['type'] != 'RBRACKET':
            lst.append(self.parse_value())
            if self.peek()['type'] == 'COMMA':
                self.advance()
        self.advance()  # consume RBRACKET
        return lst

    # Handle nested maps
    if token['type'] == 'LBRACE':
        self.advance()
        d = {}
        while self.peek()['type'] != 'RBRACE':
            key = self.expect('KEY')
            self.expect('EQUALS')
            d[key] = self.parse_value()
            if self.peek()['type'] == 'COMMA':
                self.advance()
        self.advance()  # consume RBRACE
        return d

    raise ValueError(f"Unexpected token {token['type']} at position {self.pos}")

