import asyncio
import logging
import random
from typing import Dict, Any
from dataclasses import dataclass

logger = logging.getLogger(__name__)

@dataclass
class SyncJob:
    user_id: str
    payload: Dict[str, Any]

class SyncEngine:
    """Refactored engine using asyncio.Queue, clean cancellation, and robust retry logic."""

    def __init__(self, max_workers: int = 5, max_retries: int = 3, base_delay: float = 1.0):
        self.max_workers = max_workers
        self.max_retries = max_retries
        self.base_delay = base_delay
        self.results: Dict[str, Any] = {}
        self._queue: asyncio.Queue[SyncJob] = asyncio.Queue()
        self._workers: list[asyncio.Task] = []
        self._stop_event = asyncio.Event()

    async def start(self):
        """Starts the worker pool."""
        self._workers = [
            asyncio.create_task(self._worker_loop())
            for _ in range(self.max_workers)
        ]

    async def submit(self, job: SyncJob) -> None:
        """Adds a job to the processing queue."""
        await self._queue.put(job)

    async def shutdown(self) -> None:
        """Gracefully stops the engine, draining the queue and cancelling workers."""
        self._stop_event.set()
        try:
            # Wait for all queued jobs to be processed
            await asyncio.wait_for(self._queue.join(), timeout=10.0)
        except asyncio.TimeoutError:
            logger.warning("Queue did not drain in time, forcing shutdown.")
        finally:
            # Cancel workers and wait for them to finish cleanup
            for task in self._workers:
                task.cancel()
            await asyncio.gather(*self._workers, return_exceptions=True)
            logger.info("Engine shutdown complete.")

    async def _worker_loop(self) -> None:
        """Worker loop that processes jobs from the queue."""
        while not self._stop_event.is_set():
            try:
                # Poll queue with timeout to allow checking stop event
                job = await asyncio.wait_for(
                    self._queue.get(),
                    timeout=0.5
                )
            except asyncio.TimeoutError:
                continue
            except asyncio.CancelledError:
                break

            try:
                await self._process_job(job)
            except Exception as exc:
                logger.error(f"Unhandled error processing job {job.user_id}: {exc}", exc_info=True)
            finally:
                self._queue.task_done()

    async def _process_job(self, job: SyncJob) -> None:
        """Retries processing a job with exponential backoff."""
        last_exc = None
        for attempt in range(self.max_retries):
            try:
                result = await self._execute_work(job)
                self.results[job.user_id] = {
                    "status": "success",
                    "attempt": attempt + 1,
                    "result": result
                }
                return
            except Exception as exc:
                last_exc = exc
