def detect_deadlock_cycle(graph):
    visited = set()
    path = []

    def dfs(u):
        visited.add(u)
        path.append(u)

        for v in graph.get(u, []):
            if v not in visited:
                result = dfs(v)
                if result is not None:
                    return result
            elif v in path:
                # Cycle detected: v is an ancestor in the current recursion stack
                cycle_start = path.index(v)
                return path[cycle_start:]

        # BUG FIX: The original code was missing this line.
        # When backtracking, we must remove the current node from the path
        # to ensure 'path' only represents the current recursion stack.
        # Without this, 'path' accumulates nodes from previous DFS trees,
        # causing 'v in path' to trigger false positives on nodes visited
        # in disconnected components or earlier branches.
        path.pop()
        return None

    for node in graph:
        if node not in visited:
            result = dfs(node)
            if result is not None:
                return result

    return None

