class FenwickTree:
    def __init__(self, size):
        self.n = size
        self.tree = [0] * (self.n + 1)

    def update(self, idx, delta):
        idx += 1
        while idx <= self.n:
            self.tree[idx] += delta
            idx += idx & (-idx)

    def query(self, idx):
        idx += 1
        s = 0
        while idx > 0:
            s += self.tree[idx]
            idx -= idx & (-idx)
        return s

def compute_range_sums_improved(data, queries):
    if not data:
        return [0] * len(queries)

    bit = FenwickTree(len(data))
    for i, val in enumerate(data):
        bit.update(i, val)

    results = []
    for l, r in queries:
        if l == 0:
            res = bit.query(r)
        else:
            res = bit.query(r) - bit.query(l - 1)
        results.append(res)
    return results

