import sqlite3
import json
from datetime import datetime


def schema_aware_ingest(db_path, table_name, records, type_map=None):
    if type_map is None:
        type_map = {}

    if not records:
        return {"loaded": 0, "skipped": 0, "added_columns": [], "errors": []}

    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()

    # Check if table exists
    cursor.execute(
        "SELECT name FROM sqlite_master WHERE type='table' AND name=?", 
        (table_name,)
    )
    table_exists = cursor.fetchone() is not None

    current_columns = set()
    if table_exists:
        cursor.execute(f"PRAGMA table_info('{table_name}')")
        current_columns = {col[1] for col in cursor.fetchall()}

    # Determine all columns needed
    all_keys = set()
    for r in records:
        all_keys.update(r.keys())

    # Determine columns to add and their types
    missing_columns = all_keys - current_columns
    added_columns = []
    column_types = {}

    for col in missing_columns:
        if col in type_map:
            column_types[col] = type_map[col]
        else:
            column_types[col] = "TEXT"

    # Sync schema
    # Note: DDL statements auto-commit in SQLite. We must commit after changes.
    for col in missing_columns:
        col_type = column_types[col]
        sql = f"ALTER TABLE {table_name} ADD COLUMN {col} {col_type} DEFAULT NULL"
        try:
            cursor.execute(sql)
            added_columns.append(col)
        except sqlite3.Error:
            # Ignore error if column already exists (race condition)
            pass

    conn.commit()

    # Full column list for insertion
    full_columns = sorted(current_columns | all_keys)
    cols_str = ", ".join(full_columns)
    placeholders = ", ".join(["?"] * len(full_columns))
    insert_sql = f"INSERT INTO {table_name} ({cols_str}) VALUES ({placeholders})"

    # Normalize records
    normalized_data = []
    skipped = 0
    errors = []

    for idx, record in enumerate(records):
        row_values = []
        try:
            for col in full_columns:
                val = record.get(col)
                strategy = type_map.get(col, "TEXT")

                if val is None:
                    row_values.append(None)
                elif strategy == "INT":
                    if val == "" or val is None:
                        row_values.append(None)
                    else:
                        row_values.append(int(val))
                elif strategy == "FLOAT":
                    if val == "" or val is None:
                        row_values.append(None)
                    else:
                        row_values.append(float(val))
                elif strategy == "DATETIME":
                    if isinstance(val, datetime):
                        row_values.append(val.isoformat())
                    elif isinstance(val, str):
                        # Assume valid ISO format as per spec
                        row_values.append(val)
                    else:
                        raise ValueError(f"Unexpected datetime type for col {col}")
                elif strategy == "JSON":
                    if isinstance(val, str):
                        row_values.append(val)
                    else:
                        row_values.append(json.dumps(val))
                elif strategy == "TEXT":
                    if val is None:
                        row_values.append(None)
                    else:
                        row_values.append(str(val))
                else:
                    row_values.append(val)

            normalized_data.append(row_values)

        except Exception as e:
            skipped += 1
            errors.append(f"Row {idx}: {str(e)}")

    if normalized_data:
        with conn:
            conn.executemany(insert_sql, normalized_data)

    conn.close()

    return {
        "loaded": len(normalized_data),
        "skipped": skipped,
        "added_columns": added_columns,
        "errors": errors
    }

import sqlite3
from collections import deque

class SlidingVariance:
    def __init__(self, window_size: int):
        self.window_size = window_size
        self.values = deque(maxlen=window_size)

    def step(self, value: float):
        self.values.append(value)

    def finalize(self):
        n = len(self.values)
        if n < 2:
            return None
        mean = sum(self.values) / n
        variance = sum((x - mean) ** 2 for x in self.values) / (n - 1)
        return variance

def register_sliding_variance(conn: sqlite3.Connection, window_size: int):
    conn.create_aggregate('sliding_variance', 1, SlidingVariance)

def calculate_average(score_strings):
    total_score = 0
    valid_count = 0

    for s in score_strings:
        try:
            val = int(s)
            total_score += val
            valid_count += 1
        except ValueError:
            print(f"Warning: Skipping non-numeric value '{s}'.")

    try:
        return total_score / valid_count
    except ZeroDivisionError:
        return 0.0

import json

def load_environment_config(config_path, defaults):
    try:
        with open(config_path, 'r') as f:
            data = json.load(f)
    except FileNotFoundError:
        print("Config file not found. Using defaults.")
        return dict(defaults)
    except json.JSONDecodeError:
        print("Invalid JSON. Using defaults.")
        return dict(defaults)
    except Exception:
        raise

    config = dict(defaults)
    for key, value in data.items():
        if key not in defaults:
            continue
        try:
            config[key] = type(defaults[key])(value)
        except (TypeError, ValueError):
            print(f"Skipping invalid value for {key}: {value}")
    return config

