import json
import logging
from typing import Dict, List, Any
from dataclasses import dataclass
import requests
from requests.exceptions import RequestException, Timeout
from datetime import datetime

logger = logging.getLogger(__name__)


@dataclass
class PipelineResult:
    successful: List[Dict[str, Any]]
    failed_indices: List[int]
    error_summary: Dict[str, int]


class ConfigError(Exception):
    """Raised when the configuration is invalid."""
    pass


class IngestionError(Exception):
    """Raised when a record fails validation or processing."""
    pass


def validate_config(config: Dict[str, Any]) -> str:
    """Validates the configuration and returns the endpoint."""
    endpoint = config.get("endpoint")
    if not endpoint or not isinstance(endpoint, str):
        raise ConfigError("Configuration must contain a valid 'endpoint' string.")
    return endpoint


def transform_record(record: Dict[str, Any], line_num: int) -> Dict[str, Any]:
    """Validates and transforms a raw record into a payload."""
    try:
        uid = int(record["id"])
        val = float(record.get("value", 0.0))
    except (KeyError, ValueError, TypeError) as exc:
        raise IngestionError(f"Validation failed at line {line_num}: {exc}") from exc

    return {
        "uid": uid,
        "val": val,
        "ts": datetime.now().isoformat()
    }


def send_payload(endpoint: str, payload: Dict[str, Any], retries: int = 3) -> bool:
    """Sends the payload with exponential backoff retry logic."""
    for attempt in range(retries):
        try:
            response = requests.post(endpoint, json=payload, timeout=5)

            if response.status_code == 429:
                wait_time = 2 ** attempt
                logger.warning(f"Rate limited (429). Retrying in {wait_time}s (attempt {attempt + 1}/{retries})")
                continue

            if response.ok:
                return True

            logger.warning(f"Non-2xx response {response.status_code}. Aborting for this item.")
            return False

        except Timeout:
            wait_time = 2 ** attempt
            logger.warning(f"Timeout. Retrying in {wait_time}s (attempt {attempt + 1}/{retries})")

        except RequestException as exc:
            logger.error(f"Request failed: {exc}")
            return False

    logger.error(f"Failed to send payload after {retries} attempts.")
    return False


def run_pipeline(source_path: str, config: Dict[str, Any]) -> PipelineResult:
    """Executes the data ingestion pipeline."""
    # Validate config first
    try:
        endpoint = validate_config(config)
    except ConfigError as exc:
        logger.critical(f"Configuration error: {exc}")
        raise SystemExit(1) from exc

    successful = []
    failed_indices = []
    error_summary = {}

    try:
        with open(source_path, "r", encoding="utf-8") as f:
            for line_num, line in enumerate(f, start=1):
                raw = line.strip()
                if not raw:
                    continue

                # Parse JSON
                try:
                    record = json.loads(raw)
                except json.JSONDecodeError as exc:
                    error_summary["json_parse"] = error_summary.get("json_parse", 0) + 1
                    failed_indices.append(line_num)
                    logger.debug(f"JSON parse error at line {line_num}: {exc}")
                    continue

                # Transform/Validate
                try:
                    payload = transform_record(record, line_num)
                except IngestionError as exc:
                    error_summary["validation"] = error_summary.get("validation", 0) + 1
                    failed_indices.append(line_num)
                    logger.debug(f"Validation failed at line {line_num}: {exc}")
                    continue

                # Transmit
                if send_payload(endpoint, payload):
                    successful.append(payload)
                else:
                    error_summary["transmission"] = error_summary.get("transmission", 0) + 1
                    failed_indices.append(line_num)

    except FileNotFoundError:
        logger.critical(f"Source file not found: {source_path}")
        raise SystemExit(1) from None

    except Exception as exc:
        logger.exception("Unexpected error during pipeline execution.")
        raise SystemExit(1) from exc

    result = PipelineResult(
        successful=successful,
        failed_indices=failed_indices,
        error_summary=error_summary
    )

    logger.info(
        f"Pipeline completed: {len(successful)} successes, "
        f"{len(failed_indices)} failures. Summary: {error_summary}"
    )

    return result

