def aggregate_inventory(paths):
    """
    Aggregates inventory data from a list of JSON files.

    Handles file I/O errors, JSON parsing errors, schema validation, and type errors.
    Returns partial results if some files cannot be processed.
    """
    total_qty = 0
    details = {}

    for path in paths:
        try:
            with open(path, 'r') as f:
                try:
                    data = json.load(f)
                except json.JSONDecodeError as e:
                    logger.error(f"Failed to parse JSON in {path}: {e}")
                    continue

                # Validate schema
                if not isinstance(data, dict) or 'inventory' not in data:
                    logger.error(f"Invalid schema in {path}: missing 'inventory' key.")
                    continue

                items = data['inventory']
                if not isinstance(items, list):
                    logger.error(f"Invalid schema in {path}: 'inventory' is not a list.")
                    continue

                for item in items:
                    try:
                        name = item['name']
                        qty = item['quantity']

                        # Validate types
                        if not isinstance(qty, (int, float)):
                            logger.warning(f"Invalid quantity type for item '{name}' in {path}. Skipping.")
                            continue

                        details[name] = details.get(name, 0) + qty
                        total_qty += qty

                    except KeyError as e:
                        logger.warning(f"Missing key {e} in item from {path}. Skipping item.")
                    except TypeError as e:
                        logger.error(f"Type error processing item in {path}: {e}")

        except FileNotFoundError:
            logger.error(f"File not found: {path}")
        except PermissionError:
            logger.error(f"Permission denied: {path}")
        except Exception as e:
            logger.exception(f"Unexpected error processing {path}: {e}")

    return {'total': total_qty, 'details': details}

