import logging
import time
import random
from functools import wraps
from dataclasses import dataclass, field
from typing import Dict, List, Any, Optional
from enum import Enum

logger = logging.getLogger("DataSyncService")

# 1. Custom Exception Hierarchy
class SyncError(Exception):
    """Base exception for synchronization operations."""
    pass

class TransientError(SyncError):
    """Indicates a temporary failure that might be resolved by retrying."""
    pass

class RateLimitError(TransientError):
    """Indicates the source is rate-limiting the request."""
    pass

class PermanentError(SyncError):
    """Indicates a failure that will not be resolved by retrying."""
    pass

# 2. Result Data Structure
@dataclass
class SyncResult:
    source: str
    status: str  # 'success', 'failed', 'skipped'
    data: Optional[Any] = None
    error: Optional[str] = None

# 3. Circuit Breaker Pattern
class CircuitBreakerState(Enum):
    CLOSED = "closed"
    OPEN = "open"
    HALF_OPEN = "half_open"

class CircuitBreaker:
    def __init__(self, failure_threshold: int = 5, recovery_timeout: float = 60.0):
        self.failure_threshold = failure_threshold
        self.recovery_timeout = recovery_timeout
        self.failure_count = 0
        self.last_failure_time: Optional[float] = None
        self._state = CircuitBreakerState.CLOSED

    @property
    def state(self) -> CircuitBreakerState:
        if self._state == CircuitBreakerState.OPEN:
            if self.last_failure_time and (time.time() - self.last_failure_time > self.recovery_timeout):
                self._state = CircuitBreakerState.HALF_OPEN
        return self._state

    def record_success(self):
        self.failure_count = 0
        self._state = CircuitBreakerState.CLOSED

    def record_failure(self):
        self.failure_count += 1
        self.last_failure_time = time.time()
        if self.failure_count >= self.failure_threshold:
            self._state = CircuitBreakerState.OPEN

    def allow_request(self) -> bool:
        return self.state in (CircuitBreakerState.CLOSED, CircuitBreakerState.HALF_OPEN)

# 4. Retry Decorator
def retry(max_retries: int = 3, base_delay: float = 1.0, backoff_factor: float = 2.0, jitter: bool = True):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            last_exception = None
            for attempt in range(max_retries + 1):
                try:
                    return func(*args, **kwargs)
                except RateLimitError as e:
                    last_exception = e
                    delay = base_delay * (backoff_factor ** attempt)
                    if jitter:
                        delay += random.uniform(0, delay * 0.5)
                    logger.warning(
                        f"Rate limit hit on {func.__name__} (attempt {attempt + 1}/{max_retries + 1}). "
                        f"Retrying in {delay:.2f}s."
                    )
                    time.sleep(delay)
                except TransientError as e:
                    last_exception = e
                    delay = base_delay * (backoff_factor ** attempt)
                    if jitter:
                        delay += random.uniform(0, delay * 0.5)
                    logger.warning(
                        f"Transient error on {func.__name__}: {e} (attempt {attempt + 1}/{max_retries + 1}). "
                        f"Retrying in {delay:.2f}s."
                    )
                    time.sleep(delay)
                except PermanentError as e:
                    logger.error(f"Permanent error on {func.__name__}: {e}. Aborting retries.")
                    raise
                except Exception as e:
                    logger.error(f"Unexpected error on {func.__name__}: {e}", exc_info=True)
                    raise SyncError(f"Unexpected failure in {func.__name__}") from e
            raise last_exception
        return wrapper
    return decorator

# 5. Refactored Service
class DataSyncService:
    def __init__(self, sources: List[str]):
        self.sources = sources
        self.cache: Dict[str, Any] = {}
        self.breakers = {s: CircuitBreaker() for s in sources}

    def sync_all(self) -> List[SyncResult]:
        results = []
        for source in self.sources:
            try:
                data = self.fetch_data(source)
                self.cache[source] = data
                results.append(SyncResult(source=source, status="success", data=data))
            except SyncError as e:
                results.append(SyncResult(source=source, status="failed", error=str(e)))
            except Exception as e:
                logger.critical(f"Unexpected failure syncing {source}: {e}")
                results.append(SyncResult(source=source, status="failed", error=f"Internal error: {e}"))
        return results

    @retry(max_retries=3, base_delay=0.5, backoff_factor=2, jitter=True)
    def fetch_data(self, source: str) -> Dict[str, Any]:
        breaker = self.breakers[source]
        if not breaker.allow_request():
            raise PermanentError(f"Circuit breaker open for source '{source}'")

        if source in self.cache:
            return self.cache[source]

        try:
            # Simulate fetching logic
            if source == "dead_source":
                # Simulate connection timeout
                raise ConnectionError("Connection timed out after 5s")

            if source == "rate_limit":
                # Simulate HTTP 429
                raise Exception("HTTP 429 Too Many Requests")

            if source == "bad_data":
                # Simulate JSON parse error
                raise ValueError("Expecting property name delimiter: line 1 column 2")

            # Simulate successful fetch with side effect (file write)
            temp_file = f"/tmp/sync_{source}.json"
            with open(temp_file, "w") as f:
                f.write('{"data": 1}')

            # Simulate random instability for testing circuit breaker
            if source == "unstable_db":
                if random.random() < 0.3:
                    raise ConnectionError("Intermittent timeout")

            result = {"source": source, "data": 1}
            breaker.record_success()
            return result

        except ConnectionError as e:
            breaker.record_failure()
            raise TransientError(f"Connection failed for '{source}': {e}") from e
        except ValueError as e:
            # Malformed data is permanent
            raise PermanentError(f"Malformed data from '{source}': {e}") from e
        except Exception as e:
            if "429" in str(e):
                raise RateLimitError(str(e))
            if "timeout" in str(e).lower():
                breaker.record_failure()
                raise TransientError(f"Timeout for '{source}': {e}") from e
            raise

