import pandas as pd
import argparse
import os

class CSVProcessor:
    def __init__(self, input_file, output_file, threshold):
        self.input_file = input_file
        self.output_file = output_file
        self.threshold = threshold
        self.chunk_size = 1000
        self.headers_written = False

    def process_chunk(self, chunk):
        return chunk[chunk['value'] > self.threshold]

    def write_chunk_to_file(self, chunk):
        if not self.headers_written:
            chunk.to_csv(self.output_file, mode='w', index=False, header=True)
            self.headers_written = True
        else:
            chunk.to_csv(self.output_file, mode='a', index=False, header=False)

    def process_and_write(self):
        try:
            with pd.read_csv(self.input_file, chunksize=self.chunk_size) as reader:
                for chunk in reader:
                    filtered_chunk = self.process_chunk(chunk)
                    self.write_chunk_to_file(filtered_chunk)
        except FileNotFoundError as e:
            print(f'Error: {e.strerror} - {e.filename}')
        except Exception as e:
            print(f'An unexpected error occurred: {str(e)}')

def main():
    parser = argparse.ArgumentParser(description='Process a large CSV file by filtering rows.')
    parser.add_argument('input_file', help='Path to the input CSV file')
    parser.add_argument('output_file', help='Path to the output CSV file')
    parser.add_argument('threshold', type=float, help='Threshold value for filtering')
    args = parser.parse_args()

    processor = CSVProcessor(args.input_file, args.output_file, args.threshold)
    processor.process_and_write()

if __name__ == '__main__':
    main()
