def process_data(file_path):
    if file_path.endswith('.json'):
        try:
            with open(file_path, 'r') as file:
                data = json.load(file)
        except (json.JSONDecodeError, FileNotFoundError) as e:
            logging.error(f'Error reading {file_path}: {e}')
