    Queue* queue = createQueue();
    enqueue(queue, 10);
    enqueue(queue, 20);
    enqueue(queue, 30);
    assert(dequeue(queue) == 10);
    assert(dequeue(queue) == 20);
    assert(dequeue(queue) == 30);
    assert(isEmpty(queue));
    enqueue(queue, 40);
    enqueue(queue, 50);
    assert(dequeue(queue) == 40);
    assert(dequeue(queue) == 50);
    assert(isEmpty(queue));
    free(queue);
    return 0;
