#define MAX_CHAR 256

int findLongestSubstring(const char *str, int k) {
    int n = strlen(str);
    int count[MAX_CHAR] = {0};
    int distinctCount = 0;
    int left = 0, right = 0, maxLength = 0;

    while (right < n) {
        // Increment the count of the current character
        count[str[right]]++;

        // Check if this character is being considered for the first time
        if (count[str[right]] == 1) {
            distinctCount++;
        }

        // If the distinct character count is more than k,
        // remove characters from the left until distinct count <= k
        while (distinctCount > k) {
            // Decrement the count of the current left character
            count[str[left]]--;

            // If the count becomes 0, then this character is no longer in the window
            if (count[str[left]] == 0) {
                distinctCount--;
