#include <stddef.h>

void reverse_string(char *str) {
    if (str == NULL) return;

    char *start = str;
    char *end = str;

    // Move end to the last character
    while (*end != '\0') {
        end++;
    }
    end--;

    // Swap characters from start to end
    while (start < end) {
        char temp = *start;
        *start = *end;
        *end = temp;

        start++;
        end--;
    }
}

