```c
struct ListNode {
    int val;
    struct ListNode *next;
};

struct ListNode* reverseList(struct ListNode* head);
```

Your tests should cover at least the following scenarios:
- Reversing an empty list.
- Reversing a list with one node.
- Reversing a list with multiple nodes.
- Reversing a list with duplicate values.

Write the function `reverseList` and the corresponding unit tests in a style that resembles pytest assertions.

#include <stdio.h>
#include <stdlib.h>
#include <assert.h>

struct ListNode {
    int val;
    struct ListNode *next;
};

struct ListNode* reverseList(struct ListNode* head) {
    struct ListNode *prev = NULL, *current = head, *next = NULL;
    while (current != NULL) {
        next = current->next;       // Store next
        current->next = prev;       // Reverse current node's pointer
        prev = current;             // Move pointers one position ahead.
        current = next;
    }
    head = prev;
    return head;
}

// Helper function to create a new node
struct ListNode* newNode(int val) {
    struct ListNode* node = (struct ListNode*) malloc(sizeof(struct ListNode));
    node->val = val;
    node->next = NULL;
    return node;
}

// Helper function to compare two linked lists
int compareLists(struct ListNode* a, struct ListNode* b) {
    while (a && b) {
        if (a->val != b->val) return 0;
        a = a->next;
        b = b->next;
    }
    return (a == NULL && b == NULL);
}

// Helper function to free the linked list
void freeList(struct ListNode* head) {
    struct ListNode* temp;
    while (head) {
        temp = head;
        head = head->next;
        free(temp);
    }
}
