void removeElement(DynamicArray *da, int index) {
    if (index < 0 || index >= da->size) {
        fprintf(stderr, "Index out of bounds\n");
        return;
    }
    // Shift elements to the left
    for (int i = index; i < da->size - 1; i++) {
        da->array[i] = da->array[i + 1];
    }
    // Decrease size
    da->size--;
}

