#include <string.h>

void rotate_string(char *str, int n) {
    if (!str || n <= 0) return;
    int len = strlen(str);
    if (len <= 1) return;
    n = n % len;  // Handle cases where n is greater than the length of the string
    // Reverse the entire string
    for (int i = 0, j = len - 1; i < j; i++, j--) {
        char temp = str[i];
        str[i] = str[j];
        str[j] = temp;
    }
    // Reverse the first n characters
    for (int i = 0, j = n - 1; i < j; i++, j--) {
        char temp = str[i];
        str[i] = str[j];
        str[j] = temp;
