#include <stdio.h>
#include <stdlib.h>
#include <ctype.h>
#include <string.h>

#define MAX_TOKENS 100
#define MAX_STACK 100
#define MAX_TOKEN_LEN 10

typedef enum { NUMBER, OPERATOR, LPAREN, RPAREN } TokenType;

typedef struct {
    TokenType type;
    char value[MAX_TOKEN_LEN];
} Token;

int precedence(char op) {
    if (op == '+' || op == '-')
        return 1;
    if (op == '*' || op == '/')
        return 2;
    return 0;
}

int apply_operator(int a, int b, char op) {
    switch (op) {
        case '+': return a + b;
        case '-': return a - b;
        case '*': return a * b;
        case '/': return a / b;
        default: return 0;
    }
}

int is_operator(char c) {
    return c == '+' || c == '-' || c == '*' || c == '/' || c == '(' || c == ')';
}

int parse_expression(Token tokens[], int token_count) {
    int stack[MAX_STACK];
    int top = -1;
    int i;
    int value;
    char op;

    for (i = 0; i < token_count; i++) {
        if (tokens[i].type == NUMBER) {
            value = atoi(tokens[i].value);
            stack[++top] = value;
        } else if (tokens[i].type == OPERATOR) {
            while (top > 0 && precedence(tokens[i].value[0]) <= precedence(stack[top])) {
                op = stack[top--];
                value = apply_operator(stack[top--], stack[top--], op);
                stack[++top] = value;
            }
            stack[++top] = tokens[i].value[0];
        } else if (tokens[i].type == LPAREN) {
            stack[++top] = tokens[i].value[0];
        } else if (tokens[i].type == RPAREN) {
            while (stack[top] != '(') {
                op = stack[top--];
                value = apply_operator(stack[top--], stack[top--], op);
                stack[++top] = value;
            }
            top--;
        }
    }

    while (top > 1) {
        op = stack[top--];
        value = apply_operator(stack[top--], stack[top--], op);
        stack[++top] = value;
    }

    return stack[top];
}

int main() {
    Token tokens[MAX_TOKENS] = {0};
    int token_count = 0;
    char expression[MAX_TOKENS * MAX_TOKEN_LEN] = {0};
    char token[MAX_TOKEN_LEN] = {0};
    int i = 0;

    printf("Enter an arithmetic expression: ");
    fgets(expression, sizeof(expression), stdin);

    while (sscanf(expression + i, "%s%n", token, &i) == 1) {
        if (isdigit(token[0]) || (token[0] == '-' && isdigit(token[1]))) {
            tokens[token_count].type = NUMBER;
            strcpy(tokens[token_count].value, token);
        } else if (is_operator(token[0])) {
            if (token[0] == '(') {
                tokens[token_count].type = LPAREN;
            } else if (token[0] == ')') {
                tokens[token_count].type = RPAREN;
            } else {
                tokens[token_count].type = OPERATOR;
            }
            tokens[token_count].value[0] = token[0];
            tokens[token_count].value[1] = '\0';
        }
        token_count++;
    }

    int result = parse_expression(tokens, token_count);
    printf("Result: %d\n", result);

    return 0;
}

