#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#define MAX_LINE 256
#define MAX_ELEMENTS 100

typedef struct {
    int depth;
    char name[MAX_LINE];
} Element;

Element elements[MAX_ELEMENTS];
int elementCount = 0;

int isValidXML(const char* line) {
    // Simple validation: check for mismatched tags
    int openCount = 0, closeCount = 0;
    char* ptr = line;

    while (*ptr) {
        if (*ptr == '<' && ptr[1] != '/')
            openCount++;
        else if (*ptr == '<' && ptr[1] == '/')
            closeCount++;
        ptr++;
    }

    return openCount == closeCount;
}

void parseXML(const char* filename) {
    FILE* file = fopen(filename, "r");
    char line[MAX_LINE];

    if (!file) {
        printf("Error opening file\n");
        return;
    }

    int currentDepth = 0;

    while (fgets(line, MAX_LINE, file)) {
        char* start = strchr(line, '<');
        char* end = strchr(line, '>');

        if (start && end && start < end) {
            *end = '\0';
            if (start[1] != '/') { // Opening tag
                start++;
                currentDepth++;
                printf("%*sElement: %s\n", currentDepth * 2, "", start);
                strcpy(elements[elementCount].name, start);
                elements[elementCount].depth = currentDepth;
                elementCount++;
            } else { // Closing tag
                start += 2;
                currentDepth--;
                if (elementCount > 0 && strcmp(elements[elementCount - 1].name, start) == 0) {
                    printf("%*sClosing Element: %s\n", currentDepth * 2, "", start);
                    elementCount--;
                } else {
                    printf("Mismatched closing tag: %s\n", start);
                }
            }
        }
    }

    if (currentDepth != 0) {
        printf("Unclosed elements detected\n");
    }

    fclose(file);
}

