Here is the custom component definition and usage:

```html
<template id='item-list-template'>
  <ul>
    <li>Item: {{item}}</li>
  </ul>
</template>

<item-list items='["Apple", "Banana", "Cherry"]'></item-list>

<script>
  class ItemList extends HTMLElement {
    constructor() {
      super();
      const template = document.getElementById('item-list-template');
      const templateContent = template.content;
      this.attachShadow({ mode: 'open' }).appendChild(templateContent.cloneNode(true));
    }

    connectedCallback() {
      const items = this.getAttribute('items');
      const listItems = this.shadowRoot.querySelectorAll('li');
      listItems.forEach((li, index) => {
        li.textContent = `Item: ${items[index]}`;
      });
