import java.util.ArrayList;
import java.util.ConcurrentModificationException;
import java.util.Iterator;

public class InventoryManager<T> {
    private ArrayList<T> items;

    public InventoryManager() {
        items = new ArrayList<>();
    }

    public synchronized void addItem(T item) {
        if (item == null) {
            throw new IllegalArgumentException("Item cannot be null");
        }
        items.add(item);
    }

    public synchronized T removeItem(int index) {
        if (index < 0 || index >= items.size()) {
            throw new IndexOutOfBoundsException("Index out of bounds: " + index);
        }
        return items.remove(index);
    }

    public synchronized int getItemCount() {
        return items.size();
    }

    public synchronized Iterator<T> getItemsIterator() {
        return new Iterator<T>() {
            private final int expectedModCount = items.size();
            private int currentIndex = 0;

            @Override
            public boolean hasNext() {
                if (expectedModCount != items.size()) {
                    throw new ConcurrentModificationException("Inventory modified during iteration");
                }
                return currentIndex < items.size();
            }

            @Override
            public T next() {
                if (!hasNext()) {
                    throw new NoSuchElementException();
                }
                return items.get(currentIndex++);
            }
        };
    }
}

