import java.util.concurrent.locks.Lock;
import java.util.concurrent.locks.ReentrantLock;
import java.util.logging.Logger;

public class Library {
    private static volatile Library instance;
    private int totalBooks;
    private int borrowedBooks;
    private static final Lock lock = new ReentrantLock();
    private static final Logger logger = Logger.getLogger(Library.class.getName());

    private Library(int totalBooks) {
        this.totalBooks = totalBooks;
        this.borrowedBooks = 0;
    }

    public static Library getInstance(int totalBooks) {
        if (instance == null) {
            lock.lock();
            try {
                if (instance == null) {
                    instance = new Library(totalBooks);
                }
            } finally {
                lock.unlock();
            }
        }
        return instance;
    }

    public void borrowBook() {
        lock.lock();
        try {
            if (borrowedBooks < totalBooks) {
                borrowedBooks++;
                logger.info("Book borrowed. Books remaining: " + (totalBooks - borrowedBooks));
            } else {
                logger.info("No more books available.");
            }
        } finally {
            lock.unlock();
        }
    }

    public void returnBook() {
        lock.lock();
        try {
            if (borrowedBooks > 0) {
                borrowedBooks--;
                logger.info("Book returned. Books remaining: " + (totalBooks - borrowedBooks));
            } else {
                logger.info("No books to return.");
            }
        } finally {
            lock.unlock();
        }
    }
}

public class AlternatingPrinter {
    private final int n;
    private final int m;
    private int currentNumber = 1;
    private final Object lock = new Object();

    public AlternatingPrinter(int n, int m) {
        this.n = n;
        this.m = m;
    }

    public void printAlternatingNumbers() {
        Thread thread1 = new Thread(() -> {
            for (int i = 0; i < n; i++) {
                synchronized (lock) {
                    while (currentNumber <= m) {
                        try {
                            lock.wait();
                        } catch (InterruptedException e) {
                            Thread.currentThread().interrupt();
                        }
                    }
                    System.out.print(currentNumber++ + ", ");
                    lock.notify();
                }
            }
        });

        Thread thread2 = new Thread(() -> {
            for (int i = 0; i < n; i++) {
                synchronized (lock) {
                    while (currentNumber > m) {
                        try {
                            lock.wait();
                        } catch (InterruptedException e) {
                            Thread.currentThread().interrupt();
                        }
                    }
                    System.out.print(currentNumber++ + ", ");
                    lock.notify();
                }
            }
        });

        thread1.start();
        thread2.start();
        try {
            thread1.join();
            thread2.join();
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }

    public static void main(String[] args) {
        AlternatingPrinter printer = new AlternatingPrinter(3, 5);
        printer.printAlternatingNumbers();
    }
}

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.BlockingQueue;
import java.util.concurrent.LinkedBlockingQueue;
import java.util.concurrent.Semaphore;

public class ConcurrentQueueProcessor {

    public static List<Integer> processAndMerge(BlockingQueue<Integer> queue1, BlockingQueue<Integer> queue2) {
        List<Integer> result = new ArrayList<>();
        Semaphore semaphore = new Semaphore(1);

        Thread thread1 = new Thread(() -> processQueue(queue1, result, semaphore));
        Thread thread2 = new Thread(() -> processQueue(queue2, result, semaphore));

        thread1.start();
        thread2.start();

        try {
            thread1.join();
            thread2.join();
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }

        result.sort(Integer::compareTo);
        return result;
    }

    private static void processQueue(BlockingQueue<Integer> queue, List<Integer> result, Semaphore semaphore) {
        try {
            while (true) {
                Integer number = queue.poll();
                if (number == null) {
                    break;
                }
                semaphore.acquire();
                result.add(number);
                semaphore.release();
            }
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }

    public static void main(String[] args) {
        BlockingQueue<Integer> queue1 = new LinkedBlockingQueue<>();
        BlockingQueue<Integer> queue2 = new LinkedBlockingQueue<>();

        try {
            queue1.put(5);
            queue1.put(3);
            queue2.put(8);
            queue2.put(2);
            queue2.put(7);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }

        List<Integer> mergedList = processAndMerge(queue1, queue2);
        System.out.println(mergedList); // Output should be [2, 3, 5, 7, 8]
    }
}

