import java.util.LinkedList;
import java.util.Queue;

public class ProducerConsumer {
    private static final int BUFFER_SIZE = 10;
    private Queue<Integer> buffer = new LinkedList<>();
    private boolean isProducing = true;

    public static void main(String[] args) {
        ProducerConsumer pc = new ProducerConsumer();
        Thread producer = new Thread(pc.new Producer());
        Thread consumer = new Thread(pc.new Consumer());

        producer.start();
        consumer.start();
    }

    class Producer implements Runnable {
        @Override
        public void run() {
            while (isProducing) {
                synchronized (buffer) {
                    while (buffer.size() == BUFFER_SIZE) {
                        try {
                            System.out.println("Producer waiting, buffer is full.");
                            buffer.wait();
                        } catch (InterruptedException e) {
                            Thread.currentThread().interrupt();
                        }
                    }
                    int value = (int) (Math.random() * 100);
                    buffer.add(value);
                    System.out.println("Produced: " + value);
                    buffer.notifyAll();
                }
            }
            synchronized (buffer) {
                buffer.notifyAll(); // Notify consumers that no more items will be produced
            }
        }
    }

    class Consumer implements Runnable {
        @Override
        public void run() {
            while (true) {
                synchronized (buffer) {
                    while (buffer.isEmpty() && isProducing) {
                        try {
                            System.out.println("Consumer waiting, buffer is empty.");
                            buffer.wait();
                        } catch (InterruptedException e) {
                            Thread.currentThread().interrupt();
                        }
                    }
                    if (buffer.isEmpty() && !isProducing) {
                        // If buffer is empty and production is stopped, exit
                        break;
                    }
                    int value = buffer.remove();
                    System.out.println("Consumed: " + value);
                    buffer.notifyAll();
                }
            }
        }
    }
}

