import java.io.*;

class FileMergeException extends Exception {
    public FileMergeException(String message) {
        super(message);
    }
}

public class FileMerger {
    public static boolean mergeFiles(String file1Path, String file2Path, String outputPath) {
        BufferedReader reader1 = null;
        BufferedReader reader2 = null;
        BufferedWriter writer = null;
        try {
            reader1 = new BufferedReader(new FileReader(file1Path));
            reader2 = new BufferedReader(new FileReader(file2Path));
            writer = new BufferedWriter(new FileWriter(outputPath));

            String line1 = reader1.readLine();
            String line2 = reader2.readLine();
            while (line1 != null || line2 != null) {
                if (line1 != null) {
                    writer.write(line1);
                    writer.newLine();
                    line1 = reader1.readLine();
                }
                if (line2 != null) {
                    writer.write(line2);
                    writer.newLine();
                    line2 = reader2.readLine();
                }
            }
            return true;
        } catch (FileNotFoundException e) {
            throw new FileMergeException("One or both input files do not exist or are not accessible.");
        } catch (IOException e) {
            System.err.println("An I/O error occurred: " + e.getMessage());
            return false;
        } finally {
            try {
                if (reader1 != null) reader1.close();
                if (reader2 != null) reader2.close();
                if (writer != null) writer.close();
            } catch (IOException e) {
                System.err.println("Failed to close a file: " + e.getMessage());
