public class CsvTransformer {

    public void transform(InputStream inputStream, OutputStream outputStream) throws IOException {
        try (BufferedReader reader = new BufferedReader(new InputStreamReader(inputStream));
             BufferedWriter writer = new BufferedWriter(new OutputStreamWriter(outputStream))) {

            String header = reader.readLine();
            if (header == null) {
                throw new IOException("Empty input file");
            }
            writer.write(toUpperCase(header));
            writer.newLine();

            String line;
            while ((line = reader.readLine()) != null) {
                writer.write(toUpperCase(line));
                writer.newLine();
            }
        }
    }

    private String toUpperCase(String line) {
        String[] parts = line.split(",");
        for (int i = 0; i < parts.length; i++) {
            parts[i] = parts[i].toUpperCase();
        }
        return String.join(",", parts);
    }
}

