public class FileMerger {

    public static void mergeFiles(String file1, String file2, String outputFile) throws IOException {
        try (BufferedReader reader1 = new BufferedReader(new FileReader(file1));
             BufferedReader reader2 = new BufferedReader(new FileReader(file2));
             BufferedWriter writer = new BufferedWriter(new FileWriter(outputFile))) {

            String line1 = reader1.readLine();
            String line2 = reader2.readLine();

            while (line1 != null && line2 != null) {
                if (line1.compareTo(line2) <= 0) {
                    writer.write(line1);
                    line1 = reader1.readLine();
                } else {
                    writer.write(line2);
                    line2 = reader2.readLine();
                }
                writer.newLine(); // Ensure each line is written on a new line
            }

            // Append remaining lines from the file that still has lines left
            while (line1 != null) {
                writer.write(line1);
                line1 = reader1.readLine();
                writer.newLine();
            }

            while (line2 != null) {
                writer.write(line2);
                line2 = reader2.readLine();
                writer.newLine();
            }
