        this.logger = logger;
    }

    public double processTransactions(List<Transaction> transactions) {
        for (Transaction transaction : transactions) {
            try {
                if (!"deposit".equalsIgnoreCase(transaction.getType()) && !"withdrawal".equalsIgnoreCase(transaction.getType())) {
                    throw new IllegalArgumentException("Invalid transaction type: " + transaction.getType());
                }

                if ("withdrawal".equalsIgnoreCase(transaction.getType()) && transaction.getAmount() > balance) {
