def calculate_genre_sales(csv_file):
    import csv
    genre_sales = {}
    try:
        with open(csv_file, 'r', newline='') as file:
            reader = csv.reader(file)
            next(reader)  # Skip header row
            for row in reader:
                if len(row) < 6:
                    continue  # Skip rows with insufficient data
                genre = row[2].strip()
                sales = 0
                for sale in row[3:6]:
                    try:
                        sales += int(sale.strip())
                    except ValueError:
                        continue  # Skip invalid sales data
                if genre in genre_sales:
                    genre_sales[genre] += sales
                else:
                    genre_sales[genre] = sales
            if genre_sales:
                max_genre = max(genre_sales, key=genre_sales.get)
                print(f'The genre with the highest sales is {max_genre} with total sales of {genre_sales[max_genre]}.')
            else:
                print('No valid sales data available.')
