bool isPerfectSquare(int num) {
    if (num < 0) {
        return 0;
    }
    if (num == 0 || num == 1) {
        return 1;
    }
    int left = 1, right = num / 2;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        long square = (long)mid * mid;
        if (square == num) {
            return 1;
        } else if (square < num) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }
    return 0;
}

