int minDistance(int dist[], bool sptSet[], int num_nodes) {
    int min = INT_MAX, min_index;

    for (int v = 0; v < num_nodes; v++)
        if (sptSet[v] == false && dist[v] <= min)
            min = dist[v], min_index = v;

    return min_index;
}

int shortest_path(int start, int end, int graph[][3], int num_edges, int num_nodes) {
    int dist[num_nodes];
    bool sptSet[num_nodes];

    for (int i = 0; i < num_nodes; i++)
        dist[i] = INT_MAX, sptSet[i] = false;

    dist[start] = 0;

    for (int count = 0; count < num_nodes - 1; count++) {
        int u = minDistance(dist, sptSet, num_nodes);

        sptSet[u] = true;

        for (int i = 0; i < num_edges; i++) {
            int v = graph[i][1];
            if (graph[i][0] == u && sptSet[v] == false && dist[u] != INT_MAX && dist[u] + graph[i][2] < dist[v])
                dist[v] = dist[u] + graph[i][2];
        }
    }

    return dist[end] == INT_MAX ? -1 : dist[end];
}

