struct ListNode* rotate_linked_list(struct ListNode* head, int k) {
    if (!head || !head->next || k == 0) {
        return head;
    }

    int len = 1;
    struct ListNode *tail = head;
    while (tail->next) {
        tail = tail->next;
        len++;
    }

    k = k % len;
    if (k == 0) {
        return head;
    }

    struct ListNode *new_tail = head;
    for (int i = 0; i < len - k - 1; i++) {
        new_tail = new_tail->next;
    }

    struct ListNode *new_head = new_tail->next;
    new_tail->next = NULL;
    tail->next = head;

    return new_head;
}

