int is_palindrome(char *str) {
    int left = 0, right = strlen(str) - 1;
    while (left < right) {
        if (!isalnum(str[left])) {
            left++;
            continue;
        }
        if (!isalnum(str[right])) {
            right--;
            continue;
        }
        if (tolower(str[left]) != tolower(str[right])) {
            return 0;
        }
        left++;
        right--;
    }
    return 1;
}

