    unsigned int bits_to_reverse = (num & mask) >> start;

    // Reverse the extracted bits
    unsigned int reversed_bits = 0;
    while (bits_to_reverse) {
        reversed_bits = (reversed_bits << 1) | (bits_to_reverse & 1);
        bits_to_reverse >>= 1;
