        char *equalSign = strchr(line, '=');
        if (equalSign == NULL || equalSign == line || equalSign[1] == '\0') {
            fprintf(stderr, "Invalid line format: %s", line);
            continue;
        }

        *equalSign = '\0';
        trim(line);
        strcpy(pairs[count].key, line);
        strcpy(pairs[count].value, equalSign + 1);
        count++;

        if (count == capacity) {
            capacity *= 2;
            KeyValuePair *temp = (KeyValuePair *)realloc(pairs, capacity * sizeof(KeyValuePair));
            if (temp == NULL) {
                perror("Memory reallocation failed");
                free(pairs);
                return EXIT_FAILURE;
            }
            pairs = temp;
        }
    }

    fclose(file);

    for (int i = 0; i < count; i++) {
        printf("Key: %s, Value: %s\n", pairs[i].key, pairs[i].value);
    }

    free(pairs);
    return EXIT_SUCCESS;
}

