You are developing a file processing library in C. Your task is to implement a function that reads the contents of a file into a dynamically allocated buffer. The function should handle errors gracefully by checking for file existence, successful opening, and read operations. Complete the function `readFileContents` by filling in the gaps. The function should return the buffer containing the file contents on success, or NULL if any error occurs. Make sure to handle memory allocation failures and file errors appropriately.

```c
#include <stdio.h>
#include <stdlib.h>

char* readFileContents(const char* filename) {
    FILE* file = fopen(filename, "r");
    if (!file) {
        perror("Failed to open file");
        return NULL;
    }

    fseek(file, 0, SEEK_END);
    long fileSize = ftell(file);
    if (fileSize == -1) {
        perror("Failed to determine file size");
        fclose(file);
        return NULL;
    }

    fseek(file, 0, SEEK_SET);
    char* buffer = (char*)malloc(fileSize + 1);
    if (!buffer) {
        perror("Failed to allocate memory");
        fclose(file);
        return NULL;
    }

    size_t bytesRead = fread(buffer, 1, fileSize, file);
    if (bytesRead != (size_t)fileSize) {
        perror("Failed to read file");
        free(buffer);
        fclose(file);
        return NULL;
    }

    buffer[fileSize] = '\0';

    fclose(file);
    return buffer;
}
```

