Create a function that dynamically generates an HTML table from a given array of objects. Each object represents a row in the table. The first object in the array should be used to determine the table headers. The function should also include a feature to sort the data based on a specified column header when the header is clicked. The function should return the complete HTML string for the table, including the table headers and body.

Example data:
const data = [
  { name: 'Alice', age: 30, city: 'New York' },
  { name: 'Bob', age: 25, city: 'Los Angeles' },
  { name: 'Charlie', age: 35, city: 'Chicago' }
];

The function should be named `generateSortableTable` and should take two parameters: `data` (the array of objects) and `sortKey` (the key to sort by initially, if any). The function should return the HTML string for the table.

Example usage:
const tableHTML = generateSortableTable(data, 'age');
document.body.innerHTML = tableHTML;

function generateSortableTable(data, sortKey) {
  if (!data.length) return '<table></table>';

  const headers = Object.keys(data[0]);
  let sortedData = [...data].sort((a, b) => {
    if (sortKey) {
      return a[sortKey] > b[sortKey] ? 1 : -1;
    }
    return 0;
  });

  let html = '<table border=1>
    <thead>
      <tr>';
  headers.forEach(header => {
    html += `<th onclick="sortTable('${header}')">${header}</th>`;
  });
  html += '</tr>
    </thead>
    <tbody>';

  sortedData.forEach(row => {
    html += '<tr>';
    headers.forEach(header => {
      html += `<td>${row[header]}</td>`;
    });
    html += '</tr>';
  });

  html += '</tbody>
  </table>';
  return html;
}

function sortTable(key) {
  const table = document.querySelector('table');
  const tbody = table.querySelector('tbody');
  const rows = Array.from(tbody.rows);

  rows.sort((a, b) => {
    const aText = a.cells[key].textContent.trim();
    const bText = b.cells[key].textContent.trim();
    return aText.localeCompare(bText);
  });

  rows.forEach(row => tbody.appendChild(row));
}

