public class UniqueElementFinder {

    public static <T> List<T> findUniqueElements(List<T> inputList) {
        Map<T, Integer> elementCountMap = new HashMap<>();
        List<T> uniqueElements = new ArrayList<>();

        // Count occurrences of each element
        for (T element : inputList) {
            elementCountMap.put(element, elementCountMap.getOrDefault(element, 0) + 1);
        }

        // Collect elements that appear exactly once
        for (T element : inputList) {
            if (elementCountMap.get(element) == 1) {
                uniqueElements.add(element);
            }
        }

        return uniqueElements;
    }

    public static void main(String[] args) {
        List<Integer> numbers = List.of(1, 2, 2, 3, 4, 4, 5);
        List<Integer> uniqueNumbers = findUniqueElements(numbers);
        System.out.println(uniqueNumbers); // Output: [1, 3, 5]
    }
}

