public class CollectionUtils {

    public static <K, V extends Comparable<V>> V findMaxByKey(List<Map<K, V>> listOfMaps, K key) {
        V maxValue = null;
        for (Map<K, V> map : listOfMaps) {
            if (map.containsKey(key)) {
                V currentValue = map.get(key);
                if (maxValue == null || currentValue.compareTo(maxValue) > 0) {
                    maxValue = currentValue;
                }
            }
        }
        return maxValue;
    }
}

