public enum ConnectionPool {

    INSTANCE;

    private final String[] connections = new String[5];
    private boolean[] isAvailable = new boolean[5];

    ConnectionPool() {
        for (int i = 0; i < connections.length; i++) {
            connections[i] = "Connection " + (i + 1);
            isAvailable[i] = true;
        }
    }

    public synchronized String getConnection() {
        for (int i = 0; i < isAvailable.length; i++) {
            if (isAvailable[i]) {
                isAvailable[i] = false;
                return connections[i];
            }
        }
