public class PrimeFinder {

    public static int[] findPrimesInRange(int start, int end) {
        if (start > end) {
            return new int[0];
        }

        int numberOfThreads = Math.min(end - start + 1, 10); // Limit to 10 threads for efficiency
        Thread[] threads = new Thread[numberOfThreads];
        boolean[][] isPrime = new boolean[numberOfThreads][(end - start) / numberOfThreads + 1];

        int chunkSize = (end - start) / numberOfThreads + 1;
        for (int i = 0; i < numberOfThreads; i++) {
            final int threadIndex = i;
            threads[i] = new Thread(() -> {
                int localStart = start + threadIndex * chunkSize;
                int localEnd = Math.min(localStart + chunkSize - 1, end);
                for (int num = Math.max(localStart, 2); num <= localEnd; num++) {
                    if (isPrime(num)) {
                        isPrime[threadIndex][num - localStart] = true;
                    }
                }
            });
            threads[i].start();
        }

        for (Thread thread : threads) {
            try {
                thread.join();
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }

        List<Integer> primes = new ArrayList<>();
        for (int i = 0; i < numberOfThreads; i++) {
            int localStart = start + i * chunkSize;
            for (int j = 0; j < isPrime[i].length; j++) {
                if (isPrime[i][j]) {
                    primes.add(localStart + j);
                }
            }
        }

        return primes.stream().mapToInt(Integer::intValue).toArray();
    }

    private static boolean isPrime(int num) {
        if (num <= 1) return false;
        if (num <= 3) return true;
        if (num % 2 == 0 || num % 3 == 0) return false;
        for (int i = 5; i * i <= num; i += 6) {
            if (num % i == 0 || num % (i + 2) == 0) return false;
        }
        return true;
    }

}

import java.util.concurrent.locks.Lock;
import java.util.concurrent.locks.ReentrantLock;

public class AlternatingPrinter {
    private int current = 1;
    private final int n1;
    private final int n2;
    private final Lock lock = new ReentrantLock();
    private boolean printOdd = true;

    public AlternatingPrinter(int n1, int n2) {
        this.n1 = n1;
        this.n2 = n2;
    }

    public void printAlternating() {
        Thread oddThread = new Thread(() -> {
            while (current <= n1) {
                lock.lock();
                try {
                    while (!printOdd || current > n1) {
                        lock.wait();
                    }
                    if (current <= n1) {
                        System.out.println(current);
                        current++;
                        printOdd = false;
                        lock.notifyAll();
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    lock.unlock();
                }
            }
        });

        Thread evenThread = new Thread(() -> {
            while (current <= n2) {
                lock.lock();
                try {
                    while (printOdd || current > n2) {
                        lock.wait();
                    }
                    if (current <= n2) {
                        System.out.println(current);
                        current++;
                        printOdd = true;
                        lock.notifyAll();
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    lock.unlock();
                }
            }
        });

        oddThread.start();
        evenThread.start();
        try {
            oddThread.join();
            evenThread.join();
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }

    public static void main(String[] args) {
        AlternatingPrinter printer = new AlternatingPrinter(5, 5);
        printer.printAlternating();
    }
}

