import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;

public class DataProcessor {

    public static void main(String[] args) {
        String inputFile = "data.csv";
        String outputFile = "processed_data.csv";
        try (BufferedReader reader = new BufferedReader(new FileReader(inputFile));
             BufferedWriter writer = new BufferedWriter(new FileWriter(outputFile))) {
            processFile(reader, writer);
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    private static void processFile(BufferedReader reader, BufferedWriter writer) throws IOException {
        String line;
        while ((line = reader.readLine()) != null) {
            String[] data = line.split(",");
            String processedLine = processData(data);
            writer.write(processedLine);
            writer.newLine();
        }
    }

    private static String processData(String[] data) {
        StringBuilder processed = new StringBuilder();
        for (String item : data) {
            processed.append(trimAndUppercase(item)).append(",");
        }
        return removeTrailingComma(processed);
    }

    private static String trimAndUppercase(String item) {
        return item.trim().toUpperCase();
    }

    private static String removeTrailingComma(StringBuilder sb) {
        return sb.substring(0, sb.length() - 1);
    }
}

