    private String filePath;
    private int columnIndex;

    public CSVColumnAverageCalculator(String filePath, int columnIndex) {
        this.filePath = filePath;
        this.columnIndex = columnIndex;
    }

    public double calculateAverage() throws IOException {
        try (BufferedReader br = new BufferedReader(new FileReader(filePath))) {
            String line;
            double sum = 0.0;
            int count = 0;
            while ((line = br.readLine()) != null) {
                String[] values = line.split(",");
                if (columnIndex >= 0 && columnIndex < values.length) {
                    try {
                        sum += Double.parseDouble(values[columnIndex]);
                        count++;
                    } catch (NumberFormatException e) {
                        // Ignore non-numeric values
                    }
                }
            }
            if (count == 0) {
                throw new IllegalArgumentException("Column index is out of bounds or no numeric values found.");
            }
            return sum / count;
        } catch (FileNotFoundException e) {
            throw new IllegalArgumentException("File not found: " + filePath);
        }
    }
}

