public class ExceptionHandlingTask {

    public static double divideNumbers(String num1, String num2) throws DivisionByZeroException, InputParseException {
        try {
            int numerator = Integer.parseInt(num1);
            int denominator = Integer.parseInt(num2);
            if (denominator == 0) {
                throw new DivisionByZeroException('Cannot divide by zero');
            }
            return (double) numerator / denominator;
        } catch (NumberFormatException e) {
            throw new InputParseException('Invalid input');
        }
    }

    public static class DivisionByZeroException extends Exception {
        public DivisionByZeroException(String message) {
            super(message);
        }
    }

    public static class InputParseException extends Exception {
        public InputParseException(String message) {
            super(message);
        }
    }

    public static void main(String[] args) {
        try {
            System.out.println(divideNumbers("10", "2")); // Expected: 5.0
            System.out.println(divideNumbers("10", "0")); // Expected: DivisionByZeroException
            System.out.println(divideNumbers("ten", "2")); // Expected: InputParseException
        } catch (Exception e) {
            System.out.println(e.getMessage());
        }
    }
}

