class FileProcessor {

    private static final Logger logger = Logger.getLogger(FileProcessor.class.getName());

    public static String processAndTransferFile(String sourceFilePath, String destinationFilePath) {
        BufferedReader reader = null;
        BufferedWriter writer = null;
        try {
            reader = new BufferedReader(new FileReader(sourceFilePath));
            writer = new BufferedWriter(new FileWriter(destinationFilePath));
            String line;
            while ((line = reader.readLine()) != null) {
                String processedLine = line.toUpperCase();
                writer.write(processedLine);
                writer.newLine();
            }
            logger.info("File processed and transferred successfully.");
            return "File processed and transferred successfully.";
        } catch (FileNotFoundException e) {
            logger.severe("Source file not found: " + sourceFilePath);
            return "Error: Source file not found.";
