                    numbers.add(Integer.parseInt(line));
                } catch (NumberFormatException e) {
                    System.err.println("Invalid number found in file: " + line);
                }
            }
            double average = calculateAverage(numbers);
            System.out.println("Average: " + average);
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        } finally {
            if (reader != null) {
                try {
                    reader.close();
                } catch (IOException e) {
                    System.err.println("Error closing file: " + e.getMessage());
                }
            }
        }
    }

    private static double calculateAverage(List<Integer> numbers) {
        if (numbers.isEmpty()) {
            throw new IllegalArgumentException("List of numbers cannot be empty");
        }
        int sum = 0;
        for (Integer number : numbers) {
            sum += number;
        }
        return (double) sum / numbers.size(); // Ensure double division for accurate average
