#include <stdlib.h>

typedef struct TreeNode {
    int val;
    struct TreeNode *left;
    struct TreeNode *right;
} TreeNode;

TreeNode* createNode(int val) {
    TreeNode* newNode = (TreeNode*)malloc(sizeof(TreeNode));
    newNode->val = val;
    newNode->left = NULL;
    newNode->right = NULL;
    return newNode;
}

void inorderTraversal(TreeNode* root, int* arr, int* index) {
    if (root == NULL) return;
    inorderTraversal(root->left, arr, index);
    arr[(*index)++] = root->val;
    inorderTraversal(root->right, arr, index);
}

TreeNode* sortedArrayToBST(int* arr, int start, int end) {
    if (start > end) return NULL;
    int mid = start + (end - start) / 2;
    TreeNode* node = createNode(arr[mid]);
    node->left = sortedArrayToBST(arr, start, mid - 1);
    node->right = sortedArrayToBST(arr, mid + 1, end);
    return node;
}

TreeNode* mergeBSTs(TreeNode* root1, TreeNode* root2) {
    int arr1[1000], arr2[1000], mergedArr[2000];
    int index1 = 0, index2 = 0, mergedIndex = 0;
    inorderTraversal(root1, arr1, &index1);
    inorderTraversal(root2, arr2, &index2);
    int i = 0, j = 0;
    while (i < index1 && j < index2) {
        if (arr1[i] < arr2[j]) {
            mergedArr[mergedIndex++] = arr1[i++];
        } else {
            mergedArr[mergedIndex++] = arr2[j++];
        }
    }
    while (i < index1) mergedArr[mergedIndex++] = arr1[i++];
    while (j < index2) mergedArr[mergedIndex++] = arr2[j++];
    return sortedArrayToBST(mergedArr, 0, mergedIndex - 1);
}

void freeTree(TreeNode* root) {
    if (root == NULL) return;
    freeTree(root->left);
    freeTree(root->right);
    free(root);
}

