#include <stdlib.h>

int partition(int* nums, int left, int right) {
    int pivot = nums[right];
    int i = left;
    for (int j = left; j < right; j++) {
        if (nums[j] > pivot) {
            int temp = nums[i];
            nums[i] = nums[j];
            nums[j] = temp;
            i++;
        }
    }
    int temp = nums[i];
    nums[i] = nums[right];
    nums[right] = temp;
    return i;
}

int kth_largest_element(int* nums, int nums_size, int k) {
    int left = 0, right = nums_size - 1;
    while (left <= right) {
        int pivot_index = partition(nums, left, right);
        if (pivot_index == k - 1) {
            return nums[pivot_index];
        } else if (pivot_index < k - 1) {
            left = pivot_index + 1;
        } else {
            right = pivot_index - 1;
        }
    }
    return -1; // This line should never be reached if input is valid.
}

