void resizeArray(int** arr, size_t* currentSize, size_t newSize) {
    if (newSize == 0) {
        free(*arr);
        *arr = NULL;
        *currentSize = 0;
        return;
    }

    int* newArr = (int*)malloc(newSize * sizeof(int));
    if (newArr == NULL) {
        return; // Handle memory allocation failure
    }

    size_t copySize = *currentSize < newSize ? *currentSize : newSize;
    for (size_t i = 0; i < copySize; i++) {
        newArr[i] = (*arr)[i];
    }

    free(*arr);
    *arr = newArr;
    *currentSize = newSize;
}

