#define QUEUE_INIT_CAPACITY 4

typedef struct {
    int* arr;
    int front;
    int rear;
    int capacity;
} Queue;

Queue* createQueue(int capacity) {
    Queue* q = (Queue*)malloc(sizeof(Queue));
    q->arr = (int*)malloc(capacity * sizeof(int));
    q->capacity = capacity;
    q->front = 0;
    q->rear = -1;
    return q;
}

void enqueue(Queue* q, int item) {
    if ((q->rear + 1) % q->capacity == q->front) {
        // Queue is full, need to resize
        int new_capacity = q->capacity * 2;
        int* new_arr = (int*)malloc(new_capacity * sizeof(int));
        int i = q->front;
        int j = 0;
        while (i != (q->rear + 1) % q->capacity) {
            new_arr[j++] = q->arr[i];
            i = (i + 1) % q->capacity;
        }
        free(q->arr);
        q->arr = new_arr;
        q->front = 0;
        q->rear = j - 1;
        q->capacity = new_capacity;
    }
    q->rear = (q->rear + 1) % q->capacity;
    q->arr[q->rear] = item;
}

int dequeue(Queue* q) {
    if (q->front == (q->rear + 1) % q->capacity) {
        // Queue is empty
        return -1; // or handle error as needed
    }
    int item = q->arr[q->front];
    q->front = (q->front + 1) % q->capacity;
    return item;
}

bool isEmpty(Queue* q) {
    return q->front == (q->rear + 1) % q->capacity;
}

void freeQueue(Queue* q) {
    free(q->arr);
    free(q);
}

