typedef struct TreeNode {    int value;    struct TreeNode* left;    struct TreeNode* right;    int height;} TreeNode;

int max(int a, int b) {    return (a > b) ? a : b;}

int getHeight(TreeNode* node) {    if (node == NULL) return 0;    return node->height;}

TreeNode* createTreeNode(int value) {    TreeNode* newNode = (TreeNode*)malloc(sizeof(TreeNode));    newNode->value = value;    newNode->left = newNode->right = NULL;    newNode->height = 1;    return newNode;}

TreeNode* rightRotate(TreeNode* y) {    TreeNode* x = y->left;    TreeNode* T2 = x->right;
    x->right = y;    y->left = T2;
    y->height = max(getHeight(y->left), getHeight(y->right)) + 1;    x->height = max(getHeight(x->left), getHeight(x->right)) + 1;    return x;}

TreeNode* leftRotate(TreeNode* x) {    TreeNode* y = x->right;    TreeNode* T2 = y->left;
    y->left = x;    x->right = T2;
    x->height = max(getHeight(x->left), getHeight(x->right)) + 1;    y->height = max(getHeight(y->left), getHeight(y->right)) + 1;    return y;}

int getBalance(TreeNode* node) {    if (node == NULL) return 0;    return getHeight(node->left) - getHeight(node->right);}

TreeNode* insert(TreeNode* root, int value) {    if (root == NULL) return createTreeNode(value);
    if (value < root->value) root->left = insert(root->left, value);    else if (value > root->value) root->right = insert(root->right, value);    else return root; // Duplicate values are not allowed

    root->height = 1 + max(getHeight(root->left), getHeight(root->right));

    int balance = getBalance(root);

    // Left Left Case
    if (balance > 1 && value < root->left->value)        return rightRotate(root);

    // Right Right Case
    if (balance < -1 && value > root->right->value)        return leftRotate(root);

    // Left Right Case
    if (balance > 1 && value > root->left->value) {        root->left = leftRotate(root->left);        return rightRotate(root);    }

    // Right Left Case
    if (balance < -1 && value < root->right->value) {        root->right = rightRotate(root->right);        return leftRotate(root);    }

    return root;}

bool search(TreeNode* root, int value) {    if (root == NULL) return false;    if (root->value == value) return true;
    if (value < root->value) return search(root->left, value);    return search(root->right, value);}

void freeTree(TreeNode* root) {    if (root != NULL) {        freeTree(root->left);        freeTree(root->right);        free(root);    }}

