You are tasked with finding and fixing the bug in the following C function that implements a dynamic array to store integers. The function `dynamicArrayAdd` is supposed to add an integer to the dynamic array, and `dynamicArrayGet` is supposed to retrieve an integer from the array at a given index. However, there is a bug in the `dynamicArrayAdd` function that causes a segmentation fault when the array is resized. Identify and fix the bug.

Function Signature:
- void dynamicArrayAdd(struct DynamicArray *arr, int value);
- int dynamicArrayGet(struct DynamicArray *arr, size_t index);

Struct Definition:
- typedef struct DynamicArray {
    int *data;
    size_t size;
    size_t capacity;
} DynamicArray;

#include <stdlib.h>
#include <stdbool.h>

#define INITIAL_CAPACITY 4

typedef struct DynamicArray {
    int *data;
    size_t size;
    size_t capacity;
} DynamicArray;

void dynamicArrayInit(DynamicArray *arr) {
    arr->data = (int *)malloc(INITIAL_CAPACITY * sizeof(int));
    if (arr->data == NULL) {
        exit(EXIT_FAILURE);
    }
    arr->size = 0;
    arr->capacity = INITIAL_CAPACITY;
}

void dynamicArrayAdd(DynamicArray *arr, int value) {
    if (arr->size >= arr->capacity) {
        arr->capacity *= 2;
        int *newData = (int *)realloc(arr->data, arr->capacity * sizeof(int));
        if (newData == NULL) {
            exit(EXIT_FAILURE);
        }
        arr->data = newData;
    }
    arr->data[arr->size++] = value;
}

int dynamicArrayGet(struct DynamicArray *arr, size_t index) {
    if (index >= arr->size) {
        exit(EXIT_FAILURE);
    }
    return arr->data[index];
}

void dynamicArrayFree(DynamicArray *arr) {
    free(arr->data);
    arr->data = NULL;
    arr->size = 0;
    arr->capacity = 0;
}

tests:
#include <assert.h>

int main() {
    DynamicArray arr;
    dynamicArrayInit(&arr);

    dynamicArrayAdd(&arr, 10);
    assert(dynamicArrayGet(&arr, 0) == 10);

    dynamicArrayAdd(&arr, 20);
    assert(dynamicArrayGet(&arr, 1) == 20);

    dynamicArrayAdd(&arr, 30);
    assert(dynamicArrayGet(&arr, 2) == 30);

    dynamicArrayAdd(&arr, 40);
    assert(dynamicArrayGet(&arr, 3) == 40);

    dynamicArrayAdd(&arr, 50);
    assert(dynamicArrayGet(&arr, 4) == 50);

    dynamicArrayFree(&arr);
    return 0;
}

