};

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

struct Record {
    int id;
    char data[100];
};

void processData(const char* filename) {
    FILE* file = fopen(filename, "r");
    if (!file) {
        perror("Error opening file");
        return;
    }

    struct Record* records = NULL;
    size_t capacity = 10;
    size_t size = 0;

    records = (struct Record*)malloc(capacity * sizeof(struct Record));
    if (!records) {
        perror("Memory allocation failed");
        fclose(file);
        return;
    }

    while (!feof(file)) {
        if (size >= capacity) {
            capacity *= 2;
            struct Record* new_records = (struct Record*)realloc(records, capacity * sizeof(struct Record));
            if (!new_records) {
                perror("Memory reallocation failed");
                free(records);
                fclose(file);
                return;
            }
            records = new_records;
        }

        if (fscanf(file, "%d %99s", &records[size].id, records[size].data) != 2) {
            fprintf(stderr, "Error parsing data");
            free(records);
            fclose(file);
            return;
        }
        size++;
    }

    fclose(file);
    free(records);
}

