typedef struct ListNode {
    int val;
    struct ListNode *next;
} ListNode;

ListNode* mergeSortedLists(ListNode* list1, ListNode* list2) {
    ListNode dummy;
    ListNode* current = &dummy;

    while (list1 && list2) {
        if (list1->val < list2->val) {
            current->next = list1;
            list1 = list1->next;
        } else {
            current->next = list2;
            list2 = list2->next;
        }
        current = current->next;
    }

    if (list1) {
        current->next = list1;
    } else if (list2) {
        current->next = list2;
    }

    return dummy.next;
}

