typedef struct {
    int num_nodes;
    int** adjacency_matrix;
} Graph;

int min_distance(int* dist, bool* visited, int num_nodes) {
    int min = INT_MAX, min_index;
    for (int v = 0; v < num_nodes; v++)
        if (visited[v] == false && dist[v] <= min) {
            min = dist[v];
            min_index = v;
        }
    return min_index;
}

int shortest_path(int start, int end, const Graph* graph) {
    int num_nodes = graph->num_nodes;
    int* dist = (int*)malloc(num_nodes * sizeof(int));
    bool* visited = (bool*)malloc(num_nodes * sizeof(bool));

    for (int i = 0; i < num_nodes; i++) {
        dist[i] = INT_MAX;
        visited[i] = false;
    }

    dist[start] = 0;

    for (int count = 0; count < num_nodes - 1; count++) {
        int u = min_distance(dist, visited, num_nodes);
        visited[u] = true;

        for (int v = 0; v < num_nodes; v++)
            if (!visited[v] && graph->adjacency_matrix[u][v] != -1 &&
                dist[u] != INT_MAX &&
                dist[u] + graph->adjacency_matrix[u][v] < dist[v])
                dist[v] = dist[u] + graph->adjacency_matrix[u][v];
    }

    int result = dist[end];
    free(dist);
    free(visited);
    return result == INT_MAX ? -1 : result;
}

