// Function to find the median of two sorted arrays
// nums1 and nums2 are sorted arrays of integers
// nums1Size and nums2Size are the sizes of nums1 and nums2 respectively
// The function returns the median of the combined arrays

double findMedian(int* nums1, int nums1Size, int* nums2, int nums2Size) {
    int totalSize = nums1Size + nums2Size;
    int mid = totalSize / 2;
    int i = 0, j = 0, k = 0;
    int merged[mid + 1];

    // Merging the two sorted arrays into a single sorted array
    while (i < nums1Size && j < nums2Size && k <= mid) {
        if (nums1[i] < nums2[j]) {
            merged[k++] = nums1[i++];
        } else {
            merged[k++] = nums2[j++];
        }
    }

    // If there are remaining elements in nums1
    while (i < nums1Size && k <= mid) {
        merged[k++] = nums1[i++];
    }

    // If there are remaining elements in nums2
    while (j < nums2Size && k <= mid) {
        merged[k++] = nums2[j++];
    }

    // If the total size is even, the median is the average of the two middle elements
    if (totalSize % 2 == 0) {
        return (merged[mid - 1] + merged[mid]) / 2.0;
    }

    // If the total size is odd, the median is the middle element
    return merged[mid];
}

