#include <limits.h>

int minJumps(int* nums, int numsSize) {
    if (numsSize <= 1) return 0;
    if (nums[0] == 0) return -1;

    int maxReach = nums[0];
    int step = nums[0];
    int jump = 1;

    for (int i = 1; i < numsSize - 1; i++) {
        if (i + nums[i] > maxReach) maxReach = i + nums[i];
        step--;
        if (step == 0) {
            jump++;
            if (i >= maxReach) return -1;
            step = maxReach - i;
        }
    }

    return (maxReach >= numsSize - 1) ? jump : -1;
}

