        return result;
    }

    int *numbers = NULL;
    size_t capacity = 100;
    size_t count = 0;
    numbers = (int *)malloc(capacity * sizeof(int));
    if (!numbers) {
        fclose(inputFile);
        Result result = {0, "Failed to allocate memory"};
        return result;
    }

    char line[MAX_LINE_LENGTH];
    while (fgets(line, sizeof(line), inputFile)) {
