Implement a function named `mergeSortedFiles` that takes two file paths as input and merges their contents into a new file, maintaining the sorted order of numbers. Each input file contains a list of integers, one per line, sorted in ascending order. The function should return `true` if the merge is successful, and `false` otherwise. Define the following struct and typedef:

```c
typedef struct {
    FILE *file;
    int current;
    bool eof;
} FileReader;
```

The function signature is:

```c
bool mergeSortedFiles(const char *file1, const char *file2, const char *outputFile);
```

Ensure that the function handles file opening errors and cleans up resources properly.

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define BUFFER_SIZE 1024

typedef struct {
    FILE *file;
    int current;
    bool eof;
} FileReader;

FileReader *createFileReader(const char *filePath) {
    FileReader *reader = (FileReader *)malloc(sizeof(FileReader));
    if (!reader) return NULL;
    reader->file = fopen(filePath, "r");
    if (!reader->file) {
        free(reader);
        return NULL;
    }
    reader->eof = false;
    if (fscanf(reader->file, "%d", &reader->current) != 1) {
        reader->eof = true;
    }
    return reader;
}

void freeFileReader(FileReader *reader) {
    if (reader) {
        fclose(reader->file);
        free(reader);
    }
}

bool mergeSortedFiles(const char *file1, const char *file2, const char *outputFile) {
    FileReader *reader1 = createFileReader(file1);
    FileReader *reader2 = createFileReader(file2);
    if (!reader1 || !reader2) {
        freeFileReader(reader1);
        freeFileReader(reader2);
        return false;
    }

    FILE *outFile = fopen(outputFile, "w");
    if (!outFile) {
        freeFileReader(reader1);
        freeFileReader(reader2);
        return false;
    }

    while (!reader1->eof && !reader2->eof) {
        if (reader1->current <= reader2->current) {
            fprintf(outFile, "%d\n", reader1->current);
            if (fscanf(reader1->file, "%d", &reader1->current) != 1) {
                reader1->eof = true;
            }
        } else {
            fprintf(outFile, "%d\n", reader2->current);
            if (fscanf(reader2->file, "%d", &reader2->current) != 1) {
                reader2->eof = true;
            }
        }
    }

    while (!reader1->eof) {
        fprintf(outFile, "%d\n", reader1->current);
        if (fscanf(reader1->file, "%d", &reader1->current) != 1) {
            reader1->eof = true;
        }
    }

    while (!reader2->eof) {
        fprintf(outFile, "%d\n", reader2->current);
        if (fscanf(reader2->file, "%d", &reader2->current) != 1) {
            reader2->eof = true;
        }
    }

    fclose(outFile);
    freeFileReader(reader1);
    freeFileReader(reader2);
    return true;
}

