void reverseWords(char *s) {
    if (!s) return;

    // Helper function to reverse a portion of the string
    void reverse(char *start, char *end) {
        while (start < end) {
            char temp = *start;
            *start = *end;
            *end = temp;
            start++;
            end--;
        }
    }

    int n = strlen(s);
    reverse(s, s + n - 1); // Reverse the entire string

    char *start = s;
    for (char *end = s; *end; end++) {
        if (*end == ' ') {
            reverse(start, end - 1); // Reverse each word
            start = end + 1;
        }
    }
    reverse(start, s + n - 1); // Reverse the last word
}

