#include <stdlib.h>
#include <stddef.h>
#include <stdbool.h>
#include <string.h>
#include <stdio.h>
#include <errno.h>

enum Status {
    SUCCESS = 0,
    FILE_NOT_FOUND = -1,
    MEMORY_ALLOCATION_FAILURE = -2,
    INVALID_DATA = -3
};

struct Result {
    int data_sum;
    int error_code;
};

static bool read_file(const char *filename, unsigned char **buffer, size_t *size) {
    FILE *file = fopen(filename, "rb");
    if (!file) {
        return false;
    }

    fseek(file, 0, SEEK_END);
    *size = ftell(file);
    fseek(file, 0, SEEK_SET);

    *buffer = (unsigned char *)malloc(*size);
    if (!*buffer) {
        fclose(file);
        return false;
    }

    if (fread(*buffer, 1, *size, file) != *size) {
        free(*buffer);
        fclose(file);
        return false;
    }

    fclose(file);
    return true;
}

enum Status process_file(const char *filename, struct Result *result) {
    result->data_sum = 0;
    result->error_code = SUCCESS;

    unsigned char *buffer = NULL;
    size_t size = 0;

    if (!read_file(filename, &buffer, &size)) {
        if (errno == ENOENT) {
            result->error_code = FILE_NOT_FOUND;
        } else {
            result->error_code = MEMORY_ALLOCATION_FAILURE;
        }
        return result->error_code;
    }

    for (size_t i = 0; i < size; i++) {
        if (buffer[i] < '0' || buffer[i] > '9') {
            free(buffer);
            result->error_code = INVALID_DATA;
            return result->error_code;
        }
        result->data_sum += buffer[i] - '0';
    }

    free(buffer);
    return SUCCESS;
}

