#include <stdlib.h>

void reallocateArray(int **array, size_t *currentSize, size_t newSize) {
    if (newSize == 0) {
        free(*array);
        *array = NULL;
        *currentSize = 0;
        return;
    }

    int *newArray = (int *)realloc(*array, newSize * sizeof(int));
    if (newArray == NULL) {
        // Handle memory allocation failure, possibly free the old array
        free(*array);
        *array = NULL;
        *currentSize = 0;
        return;
    }

    *array = newArray;

    if (newSize > *currentSize) {
        for (size_t i = *currentSize; i < newSize; ++i) {
            (*array)[i] = 0;
        }
    }

    *currentSize = newSize;
}

