bool isValidParentheses(const char *s) {
    int stack[100];
    int top = -1;
    int i = 0;
    while (s[i] != '\0') {
        if (s[i] == '(' || s[i] == '{' || s[i] == '[') {
            stack[++top] = s[i];
        } else {
            if (top == -1) {
                return false;
            }
            char open = stack[top--];
            if ((open == '(' && s[i] != ')') ||
                (open == '{' && s[i] != '}') ||
                (open == '[' && s[i] != ']')) {
                return false;
            }
        }
        i++;
    }
    return top == -1;
}

