    int maxSoFar = nums[0];
    int currentMax = nums[0];
    for (int i = 1; i < numsSize; i++) {
        currentMax = (nums[i] > currentMax + nums[i]) ? nums[i] : currentMax + nums[i];
        if (currentMax > maxSoFar) {
            maxSoFar = currentMax;
        }
    }
    return maxSoFar;
}

