#include <stdlib.h>
#include <stddef.h>

typedef struct {
    int* data;
    size_t size;
    size_t capacity;
} DynamicArray;

void removeElement(DynamicArray* array, int index) {
    if (index < 0 || index >= array->size) {
        return;
    }
    for (size_t i = index; i < array->size - 1; i++) {
        array->data[i] = array->data[i + 1];
    }
    array->size--;
    if (array->size == 0) {
        free(array->data);
        array->data = NULL;
        array->capacity = 0;
    } else if (array->size * 4 <= array->capacity) {
        array->capacity /= 2;
        array->data = realloc(array->data, array->capacity * sizeof(int));
    }
