#define BUFFER_SIZE 1024

typedef struct {
    FILE *file;
    char *buffer;
    bool eof;
} FileLine;

bool readNextLine(FileLine *fl) {
    if (fgets(fl->buffer, BUFFER_SIZE, fl->file) == NULL) {
        fl->eof = true;
        return false;
    }
    fl->buffer[strcspn(fl->buffer, "\n")] = '\0';
    return true;
}

bool mergeSortedFiles(const char *file1, const char *file2, const char *outputFile) {
    FileLine fl1 = { fopen(file1, "r"), malloc(BUFFER_SIZE), false };
    FileLine fl2 = { fopen(file2, "r"), malloc(BUFFER_SIZE), false };
    FILE *out = fopen(outputFile, "w");

    if (fl1.file == NULL || fl2.file == NULL || out == NULL) {
        fclose(fl1.file);
        fclose(fl2.file);
        fclose(out);
        free(fl1.buffer);
        free(fl2.buffer);
        return false;
    }

    readNextLine(&fl1);
    readNextLine(&fl2);

    while (!fl1.eof && !fl2.eof) {
        if (strcmp(fl1.buffer, fl2.buffer) <= 0) {
            fprintf(out, "%s\n", fl1.buffer);
            readNextLine(&fl1);
        } else {
            fprintf(out, "%s\n", fl2.buffer);
            readNextLine(&fl2);
        }
    }

    while (!fl1.eof) {
        fprintf(out, "%s\n", fl1.buffer);
        readNextLine(&fl1);
    }

    while (!fl2.eof) {
        fprintf(out, "%s\n", fl2.buffer);
        readNextLine(&fl2);
    }

    fclose(fl1.file);
    fclose(fl2.file);
    fclose(out);
    free(fl1.buffer);
    free(fl2.buffer);
    return true;
}

