int find_longest_subsequence(int *arr, int n) {
    if (n == 0) return 0;

    int *dp = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        dp[i] = 1;
    }

    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (arr[i] > arr[j] && dp[i] < dp[j] + 1) {
                dp[i] = dp[j] + 1;
            }
        }
    }

    int max_length = dp[0];
    for (int i = 1; i < n; i++) {
        if (dp[i] > max_length) {
            max_length = dp[i];
        }
    }

    free(dp);
    return max_length;
}

