Implement a function to insert a new element at a specified position in a singly linked list. The list should be able to handle dynamic memory allocation and deallocation. The function should return a pointer to the head of the modified list. The list node structure is provided below. If the position is out of bounds, the function should return the original list without modification.

Function signature: node_t* insert_at_position(node_t* head, int data, int position);

Struct/typedef: typedef struct node { int data; struct node* next; } node_t;

#include <stdlib.h>

typedef struct node { int data; struct node* next; } node_t;

node_t* insert_at_position(node_t* head, int data, int position) {
    node_t* new_node = (node_t*)malloc(sizeof(node_t));
    if (new_node == NULL) {
        return head; // Memory allocation failed, return original list
    }
    new_node->data = data;
    new_node->next = NULL;

    if (position == 0) {
        new_node->next = head;
        return new_node; // Insert at the beginning
    }

    node_t* current = head;
    for (int i = 0; i < position - 1 && current != NULL; i++) {
        current = current->next;
    }

    if (current == NULL) {
        free(new_node); // Position out of bounds, free allocated memory
        return head; // Return original list
    }

    new_node->next = current->next;
    current->next = new_node;
    return head;
}

