bool merge_files(FileHandler* file1, FileHandler* file2, const char* output_filename) {
    if (!file1 || !file2 || !output_filename || !file1->filename || !file2->filename) {
        return false;
    }

    file1->file = fopen(file1->filename, "r");
    if (!file1->file) {
        return false;
    }

    file2->file = fopen(file2->filename, "r");
    if (!file2->file) {
        fclose(file1->file);
        return false;
    }

    FILE* output_file = fopen(output_filename, "w");
    if (!output_file) {
        fclose(file1->file);
        fclose(file2->file);
        return false;
    }

    char buffer1[BUFFER_SIZE];
    char buffer2[BUFFER_SIZE];

    while (fgets(buffer1, BUFFER_SIZE, file1->file)) {
        fputs(buffer1, output_file);
        if (fgets(buffer2, BUFFER_SIZE, file2->file)) {
            fputs(buffer2, output_file);
        }
    }

    while (fgets(buffer2, BUFFER_SIZE, file2->file)) {
        fputs(buffer2, output_file);
    }

    fclose(file1->file);
    fclose(file2->file);
    fclose(output_file);

    return true;
}

