        mergedArray[k++] = nums1[i++];
    }

    while (j < nums2Size) {
        mergedArray[k++] = nums2[j++];
    }

    double median;
    if (totalSize % 2 == 0) {
        median = (mergedArray[totalSize / 2 - 1] + mergedArray[totalSize / 2]) / 2.0;
