struct DynamicArray {
    int* data;
    int size;
    int capacity;
};

void initArray(struct DynamicArray* array) {
    array->data = (int*)malloc(2 * sizeof(int));
    if (array->data == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(1);
    }
    array->size = 0;
    array->capacity = 2;
}

void addElement(struct DynamicArray* array, int element) {
    if (array->size == array->capacity) {
        array->capacity *= 2;
        int* newData = (int*)realloc(array->data, array->capacity * sizeof(int));
        if (newData == NULL) {
            fprintf(stderr, "Memory reallocation failed\n");
            exit(1);
        }
        array->data = newData;
    }
    array->data[array->size] = element;
    array->size++;
}

void printArray(struct DynamicArray* array) {
    for (int i = 0; i < array->size; i++) {
        printf("%d ", array->data[i]);
    }
    printf("\n");
}

void freeArray(struct DynamicArray* array) {
    free(array->data);
    array->data = NULL;
    array->size = 0;
    array->capacity = 0;
}

