#include <string.h>

void reverseWords(char *str) {
    int len = strlen(str);
    int start = 0, end = 0;
    char temp;

    // Reverse each word in the string
    for (int i = 0; i <= len; i++) {
        if (str[i] == ' ' || str[i] == '\0') {
            end = i - 1;
            while (start < end) {
                temp = str[start];
                str[start] = str[end];
                str[end] = temp;
                start++;
                end--;
            }
            start = i + 1;
        }
    }

    // Reverse the entire string to get the words in reverse order
    start = 0;
    end = len - 1;
    while (start < end) {
        temp = str[start];
        str[start] = str[end];
        str[end] = temp;
        start++;
        end--;
    }
}

